-- =============================================================================
-- Tainted Grail Companion — database schema and initial data
-- Generated from display_ru.json (campaign Kings of Ruin, id=26)
-- =============================================================================

-- ---------------------------------------------------------------------------
-- Schema
-- ---------------------------------------------------------------------------

CREATE TABLE campaigns (
    id SERIAL PRIMARY KEY,
    source_id INTEGER UNIQUE NOT NULL,
    name TEXT NOT NULL
);

CREATE TABLE locations (
    id SERIAL PRIMARY KEY,
    campaign_id INTEGER NOT NULL REFERENCES campaigns(id) ON DELETE CASCADE,
    display_number INTEGER NOT NULL,
    name TEXT NOT NULL DEFAULT '',
    UNIQUE(campaign_id, display_number)
);

CREATE TABLE verses (
    id SERIAL PRIMARY KEY,
    location_id INTEGER NOT NULL REFERENCES locations(id) ON DELETE CASCADE,
    display_number INTEGER NOT NULL,
    UNIQUE(location_id, display_number)
);

CREATE TABLE options (
    id SERIAL PRIMARY KEY,
    verse_id INTEGER NOT NULL REFERENCES verses(id) ON DELETE CASCADE,
    position INTEGER NOT NULL,
    type TEXT NOT NULL CHECK (type IN ('choice', 'condition')),
    text TEXT NOT NULL DEFAULT '',
    target_type TEXT CHECK (target_type IN ('verse', 'cross_location', 'end')),
    target_verse_dn INTEGER,
    target_location_dn INTEGER,
    requirement TEXT,
    result TEXT,
    hidden TEXT CHECK (hidden IN ('red_filter', 'blue_filter', 'both_filters', 'filter')),
    once BOOLEAN NOT NULL DEFAULT FALSE,
    condition_group TEXT,
    conditional_targets JSONB,
    children JSONB,
    UNIQUE(verse_id, position)
);

CREATE TABLE progress (
    id SERIAL PRIMARY KEY,
    option_id INTEGER NOT NULL REFERENCES options(id) ON DELETE CASCADE,
    visited_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    visited_by BIGINT,
    UNIQUE(option_id)
);

CREATE TABLE users (
    telegram_id BIGINT PRIMARY KEY,
    username TEXT,
    role TEXT NOT NULL DEFAULT 'player' CHECK (role IN ('admin', 'player')),
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Indexes
CREATE INDEX idx_locations_campaign ON locations(campaign_id);
CREATE INDEX idx_verses_location ON verses(location_id);
CREATE INDEX idx_options_verse ON options(verse_id);
CREATE INDEX idx_progress_option ON progress(option_id);

