INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (63, 30, 3, 'choice', '1 @Energy@ Силой вломиться в повозку. Сопровождение было занято починкой повозки, а дверь выглядела незапертой. Если подгадать момент…', 'verse', 11, NULL, 'Нужно хотя бы 1 очко @Aggression@.', NULL, NULL, FALSE, NULL, NULL, NULL);
