INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (90, 41, 0, 'choice', 'Проверить итоговый результат.', 'end', NULL, NULL, NULL, '1: они жутко кряхтели и выли, отчего ваше тело болезненно изгибалось. Потеряйте 1 @Health@.  2: они пели о руках, что поднимаются из алого озера, и о чувстве утопления. Получите 1 @Terror@.  3: они пели грустную песню, что вытягивала из вас волю к жизни. Потеряйте 1 @Energy@.  4: они пели успокаивающую песню, которая дарила вам покой. Потеряйте 1 @Terror@.  5: они пели бодрящую песню о далёких землях. Получите 1 @Energy@.  6: они пели странную, нескладную песню о сказочном городе Туатане, и их слова были полны дремлющей энергии. Эта песня их вымотала. Получите 1 магию.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
