INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (103, 47, 1, 'choice', 'Отправить Кливара за парой камней. Он был необычайно умён для животного, хотя и недостаточно, чтобы отличить самоцвет от цветного стекла или золото от пирита.', 'cross_location', 219, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
