INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (202, 86, 1, 'choice', '1 @Energy@ Подойти к срезанному холму. Половина этого каменистого холма выглядит так, будто бы её срезали.', 'verse', 1, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (203, 86, 2, 'choice', '1 @Energy@ Подойти к золотому собору. Металлическая постройка блестит вдали среди пепла.', 'verse', 3, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
