INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (206, 86, 5, 'choice', '1 @Energy@ Дотянуться до растрескавшейся сферы. Оранжевая сфера размером с вашу голову парила над землёй, отражая солнечный свет.', 'verse', 5, NULL, 'Нужна глава 5—10.', NULL, NULL, FALSE, NULL, NULL, NULL);
