INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (266, 112, 0, 'choice', 'Убрать из игры событие.', 'verse', 29, NULL, NULL, 'Возьмите все случайные события, которые не находятся в колоде событий. Уберите из игры одно из них (кроме секретных) и перемешайте остальные.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (267, 112, 1, 'choice', 'Убрать из игры встречу.', 'verse', 29, NULL, NULL, 'Возьмите до 7 случайных карт встреч из одной колоды встреч. Уберите из игры одну из них, остальные замешайте обратно в колоду. Создавая колоду встреч во время подготовки к главе, не используйте удалённую встречу. Когда игра особо укажет провести именно эту встречу, сделайте это, но не возвращайте карту в колоду встреч.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (268, 112, 2, 'choice', 'Убрать из игры предмет.', 'verse', 29, NULL, NULL, 'Выберите колоду предметов на столе и возьмите из неё до 7 предметов. Уберите из игры один из них, а остальные замешайте обратно в колоду.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (269, 112, 3, 'choice', 'Сказать старику, что вам ничего не нужно.', 'verse', 37, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (113, 10, 6);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (270, 113, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
