INSERT INTO verses (id, location_id, display_number) VALUES (115, 10, 8);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (272, 115, 0, 'choice', 'Остаться и насладиться свадьбой. Вам бы не помешал отдых. Судя по подготовке, здесь будет вдоволь и еды, и выпивки.', 'verse', 14, NULL, 'Нужны все персонажи.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (273, 115, 1, 'choice', 'Отвергнуть приглашение Магнуса. Выкопать путеводный камень и забрать его себе — это невообразимо подлый поступок. Вы не хотели иметь с ним ничего общего.', 'verse', 11, NULL, 'Нужны все персонажи.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (274, 115, 2, 'choice', 'Уйти пока что. Магнус ожидал вашего решения.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (116, 10, 9);
