INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (282, 119, 3, 'choice', '1 @Energy@ Расспросить других странников на перевале.', 'verse', 25, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
