INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (285, 120, 0, 'choice', 'Освободить пленника и отправиться в ближайшую деревню за сладостями.', 'verse', 34, NULL, 'Потратьте 2 золота или 1 магию либо сбросьте 1 предмет.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (286, 120, 1, 'choice', 'Не отпускать пленника и пойти в ближайшую деревню за сладостями вместе с ним.', 'verse', 31, NULL, 'Потратьте 2 золота или 1 магию либо сбросьте 1 предмет.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (287, 120, 2, 'choice', 'Угрожать пленнику, чтобы заставить водяных духов вернуть награбленное.', 'verse', 28, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (121, 10, 14);
