INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (349, 155, 1, 'choice', '1 @Energy@ Поторговать в лагере. Запастись провизией перед уходом не помешает. Как знать, насколько далеко простирался этот лес.', 'verse', 6, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (350, 155, 2, 'choice', '1 @Energy@ Запросить аудиенцию у короля Лота.', 'end', NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, '[{"type": "choice", "text": "Спросить его, почему он боится леса.", "target": "end", "children": [{"type": "choice", "text": "Продолжить.", "target": "end", "result": "Исследование окончено."}]}, {"type": "choice", "text": "Сообщить ему о просьбе его супруги. Королеве Ольфриде это не понравится…", "target": {"location": 999, "verse": 258}, "requirement": "Нужна часть 2 достижения «Небольшая услуга»."}, {"type": "choice", "text": "Сообщить ему о просьбе его сына. Аэду это не понравится…", "target": {"location": 999, "verse": 255}, "requirement": "Нужна часть 4 достижения «Небольшая услуга»."}, {"type": "choice", "text": "Сообщить ему о просьбе близнецов. Близнецам это не понравится…", "target": {"location": 999, "verse": 251}, "requirement": "Нужна часть 3 достижения «Небольшая услуга»."}, {"type": "choice", "text": "Оставить его в покое. Сейчас не время и не место отвлекать короля.", "target": "end", "result": "Исследование окончено."}]'::jsonb);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (351, 155, 3, 'choice', '1 @Energy@ Запросить аудиенцию у супруги Лота. Говорят, красоту королевы затмевает только её острый ум.', 'end', NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, '[{"type": "condition", "text": "Если у вас есть карта секрета 12.", "target": {"verse": 2}}, {"type": "choice", "text": "Продолжить.", "target": "end", "result": "Исследование окончено.", "conditionGroup": "Если у вас есть часть 2 достижения «Небольшая услуга»."}, {"type": "choice", "text": "Продолжить.", "target": {"verse": 4}, "conditionGroup": "Если у вас есть часть 2 достижения «Наглость»."}, {"type": "condition", "text": "Если у вас есть часть 1 достижения «Наглость».", "target": {"verse": 3}}, {"type": "condition", "text": "Если развязка @GreenOutcome@.", "target": {"verse": 4}, "result": "Не получайте награду."}, {"type": "condition", "text": "В противном случае.", "target": "end", "result": "Исследование окончено."}]'::jsonb);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (352, 155, 4, 'choice', '1 @Energy@ Найти Скорбных близнецов. Дети Лота спрятаны где-то в глубине этого огромного лагеря. Чтобы их найти, придётся позолотить ручку не одному придворному.', 'verse', 8, NULL, 'Потратьте 1 золото.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (353, 155, 5, 'choice', 'Посетить квартирмейстера.', 'cross_location', 228, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (354, 155, 6, 'choice', 'Вернуться на перевал Короля.', 'end', NULL, NULL, 'Если вы проходите главу 6 или более позднюю и в этой локации находятся все персонажи.', NULL, NULL, FALSE, NULL, NULL, '[{"type": "condition", "text": "Продолжить.", "target": {"location": 1001, "verse": 800}}]'::jsonb);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (355, 155, 7, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
