INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (481, 215, 0, 'choice', '1 @Energy@ Выполнить просьбу Аэда. Всего-то час-другой с лопатой, если, конечно, вам это не слишком противно.', 'verse', 7, NULL, 'Только если у вас нет части 7 достижения «Небольшая услуга». Нужна часть 4 достижения «Небольшая услуга».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (482, 215, 1, 'choice', 'Поискать что-нибудь ценное. Похоже, это место так и стояло пустым с тех пор, как пал Лотиан. А значит, вам причитаются все ценности, что вы сможете здесь найти, правильно?', 'verse', 6, NULL, 'Нужно хотя бы 1 очко @Caution@.', NULL, NULL, FALSE, NULL, NULL, NULL);
