INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (494, 222, 0, 'choice', '2 @Energy@ Восстановить лесопилку. Заплуталый лес был совсем рядом, так что лесопилка дала бы вам возможность обеспечить замок и окрестные районы необходимыми материалами для ремонта.', 'verse', 1, NULL, 'Потратьте маркеры с карты секрета 26 в количестве 1 за персонажа.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (495, 222, 1, 'choice', '1 @Energy@ Исследовать местное кладбище. Судя по рядам ничем не примечательных надгробий, здесь хоронили бедняков из ближайших к замку поселений.', 'verse', 3, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (496, 222, 2, 'choice', 'Прочесать пустоши на севере. Из-за холмов до вас доносились отчаянные хриплые крики.', 'verse', 12, NULL, 'Только если вы проходите главу 2—4.', NULL, NULL, FALSE, NULL, NULL, NULL);
