INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (524, 235, 0, 'choice', '2 @Energy@ Построить укрепления. Рельеф местности здесь был богат на естественные преграды, которые легко приспособить для обороны.', 'end', NULL, NULL, 'Только если у вас нет части 8 достижения «Восстановление Лотиана». Потратьте маркеры с карты секрета 26 в количестве 1 за персонажа.', 'Получите часть 8 достижения «Восстановление Лотиана».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (525, 235, 1, 'choice', '1 @Energy@ Осмотреть мерцающие озёра.', 'verse', 2, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (526, 235, 2, 'choice', '1 @Energy@ Обыскать развалины домов.', 'end', NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, '[{"type": "condition", "text": "Если вы проходите главу 4—10 или у вас есть хотя бы две части достижения «Время идёт (глава 3)».", "target": "end", "result": "Развалины домов уже разграблены.  Исследование окончено."}, {"type": "condition", "text": "1—4.", "target": "end", "result": "В развалинах ничего не нашлось.   Исследование окончено."}, {"type": "condition", "text": "5—6.", "target": "end", "result": "Вы нашли бочку вполне годной сушёной рыбы в подвале заброшенного дома.  Если у вас нет части 7 достижения «Добытчик», получите 2 еды.  Получите часть 7 достижения «Добытчик».  Исследование окончено."}, {"type": "condition", "text": "7—8.", "target": "end", "result": "Вы нашли небольшое уютное укрытие у стены за огромной изразцовой печью. Место было явно обжитое, но сейчас хозяина и след простыл.  Исследование окончено."}, {"type": "condition", "text": "≥9.", "target": "end", "result": "Вы нашли тайник под половицей в одном из домов побогаче.  Если у вас нет части 8 достижения «Добытчик», получите 1 предмет Б.  Получите часть 8 достижения «Добытчик».  Исследование окончено."}]'::jsonb);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (527, 235, 3, 'choice', 'Подойти к статуе неизвестной святой.', 'end', NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, '[{"type": "choice", "text": "Вернуть подношения.", "target": "end", "requirement": "Потратьте 1 золото, 1 еду и 1 магию.", "children": [{"type": "choice", "text": "Продолжить.", "target": "end", "result": "Получите часть 4 достижения «Слухи и сплетни».  Исследование окончено."}], "conditionGroup": "Если у вас есть часть 6 достижения «Что плохо лежит»."}, {"type": "choice", "text": "Уйти.", "target": "end", "result": "Исследование окончено.", "conditionGroup": "Если у вас есть часть 6 достижения «Что плохо лежит»."}, {"type": "choice", "text": "Сделать подношение неизвестной святой.", "target": "end", "requirement": "Потратьте 1 золото, 1 еду или 1 магию.", "children": [{"type": "choice", "text": "Продолжить.", "target": "end", "result": "Получите часть 4 достижения «Слухи и сплетни».  Исследование окончено."}]}, {"type": "choice", "text": "Украсть чужие подношения.", "target": {"verse": 1}}, {"type": "choice", "text": "Уйти.", "target": "end", "result": "Исследование окончено."}]'::jsonb);
