INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (534, 239, 3, 'choice', '2 @Energy@ Попытаться пересечь болото. Путь в Южные земли будет опасным. Без серьёзной причины туда давно никто не совался.', 'cross_location', 597, 999, 'Только если вы проходите главу 4, часть 2—4, либо главу 5—10. Нужны все персонажи и все части достижения «Карта болота».', NULL, NULL, FALSE, NULL, NULL, NULL);
