INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (541, 240, 1, 'condition', '3—4.', 'end', NULL, NULL, NULL, 'Вы привлекли внимание чего‑то, бродившего по этому болоту.  Каждый член команды теряет 1 @Health@. Затем возьмите фиолетовую карту встречи и проведите её.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (542, 240, 2, 'condition', '≥5.', 'end', NULL, NULL, NULL, 'В дебрях болот таились кошмары.  Каждый член команды теряет 1 @Health@. Затем возьмите три фиолетовые карты встреч. Проведите ту, у которой больше стойкость. Положите остальные карты встреч под низ их колоды.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
