INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (644, 287, 4, 'choice', '1 @Energy@ Посетить лагерь наёмников. Лагерь, разбитый на краю леса секвой, был окружён высоким частоколом.', 'verse', 6, NULL, 'Нужны все персонажи. Только если у вас нет ни части 5 достижения «Личные дела», ни части 6 достижения «Великие деяния».', NULL, NULL, FALSE, NULL, NULL, NULL);
