INSERT INTO verses (id, location_id, display_number) VALUES (301, 25, 14);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (677, 301, 0, 'choice', 'Вызвать его на поединок за лидерство в Железной дружине. По слухам, командир наёмников не мог отказаться от прямого вызова. Это было одной из причин, почему в лагерь не пускали чужаков без должных объяснений.', NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, '[{"condition": "Продолжить.", "location": 999, "verse": 596}]'::jsonb, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (678, 301, 1, 'choice', 'Договориться о мире между лагерем наёмников и южанами.', 'verse', 15, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (679, 301, 2, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
