INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (680, 302, 0, 'choice', 'Вызвать его на поединок за лидерство в Железной дружине. По слухам, командир наёмников не мог отказаться от прямого вызова. Это было одной из причин, почему в лагерь не пускали чужаков без должных объяснений.', NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, '[{"condition": "Продолжить.", "location": 999, "verse": 596}]'::jsonb, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (681, 302, 1, 'choice', 'Продать ему информацию о местонахождении сокровищницы Сурлузы. Вряд ли королевская семья Лотиана смогла бы вывезти оттуда всё, да и наёмники, похоже, заслужили свою долю. Однако, когда Лот и его семья узнают о вашей сделке, они придут в ярость.', 'verse', 5, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (682, 302, 2, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
