INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (688, 307, 1, 'choice', '1 @Energy@ Попытаться найти путь на юг. На старых картах королевство Лотиан простиралось на много миль на юг, до самых гор, отделявших его от Фоморской провинции. Должна же где-то была остаться дорога!', 'verse', 1, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (689, 307, 2, 'choice', '1 @Energy@ Посетить хижину ведьмы.', 'verse', 3, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
