INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (694, 309, 1, 'choice', 'Поддаться зову и пролезть через стену Туатана.', 'verse', 4, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
