INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (697, 310, 1, 'choice', 'Поторговать с ней.', 'verse', 3, NULL, 'Потратьте 2 еды или 2 золота.', 'Получите одноразовый предмет «Дивосвеча», «Целебный эликсир», «Третьеглазки» или «Священные благовония» (если он доступен).  Сделайте новый выбор (в этом исследовании выбрать этот вариант больше нельзя).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (698, 310, 2, 'choice', 'Восстановить вашу магию.', 'verse', 3, NULL, 'Только если в этой локации нет @LightTT@. Потратьте 2 золота.', 'Поместите 1 @LightTT@ в эту локацию и получите столько магии, сколько у вас очков @Spirituality@.', NULL, FALSE, NULL, NULL, NULL);
