INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (712, 316, 1, 'condition', 'Если вы проходите главу 6, часть 1.', 'verse', 5, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (713, 316, 2, 'condition', 'Если вы проходите главу 6Б, 7Б или 8Б.', 'verse', 10, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (714, 316, 3, 'condition', 'Если вы проходите главу 9Б, часть 1.', 'verse', 9, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (715, 316, 4, 'choice', 'Продолжить.', 'cross_location', 987, 1001, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (317, 27, 2);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (716, 317, 0, 'choice', '1—2.', 'end', NULL, NULL, NULL, 'Как вы ни старались, результат был совсем ни на что не похож. В досаде вы отбросили деревяшку в сторону.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (717, 317, 1, 'choice', '3—4.', 'end', NULL, NULL, NULL, 'Вы неумело вырезали на деревяшке черты, отдалённо напоминавшие вас. Глядя со странным удовлетворением на свою резьбу, вы в конечном счёте решили, что она недостаточно хороша, чтобы поставить её у тропы.   Потеряйте 1 @Terror@.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (718, 317, 2, 'choice', '≥5.', 'verse', 3, NULL, NULL, 'Пусть вы и неумелый резчик, но каким‑то образом вам удалось отразить на этой деревяшке свою сущность!', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (318, 27, 3);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (719, 318, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поместите на свой планшет персонажа кубик любой стороной вверх. В следующий раз, когда вам нужно будет бросить кубик, вы можете не бросать его, а использовать этот результат.  Но если кубик нужно бросить любому персонажу, не состоящему в вашей команде, он должен будет взять кубик с вашего планшета персонажа. Тогда описанная выше возможность пропадёт.  Если какое‑нибудь другое действие (например, сохранение игры) потребует использовать кубик или убрать его с планшета персонажа, описанная возможность также пропадёт.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (319, 27, 4);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (720, 319, 0, 'choice', 'Поставить свечку бродячей повитухе. На этом покосившемся деревянном столбе была изображена пожилая женщина с мешочками трав и пузырьками мазей. Ваш взгляд привлекло то, что она держала в руках: это была тряпичная кукла человеческого зародыша, соединённая нитью-пуповиной с лоскутной утробой.', 'end', NULL, NULL, 'Только если у вас нет части 1 достижения «Путники из прошлого».', 'Получите часть 1 достижения «Путники из прошлого».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (721, 319, 1, 'choice', 'Поставить свечку угрюмому следопыту. Этот искусно вырезанный истукан изображал высокого сурового следопыта, увешанного амулетами и дивосвечами. Он опирался на окованный железом посох и взирал на вас пронзительным печальным взглядом. На вершине посоха красовался необычный набалдашник — многопалая каменная рука, такая же, как на путеводных камнях.', 'end', NULL, NULL, 'Только если у вас нет части 2 достижения «Путники из прошлого».', 'Получите часть 2 достижения «Путники из прошлого».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (722, 319, 2, 'choice', 'Поставить свечку древнему мореходу. Наряд, да и весь внешний вид этого человека, больше подходившие для открытого моря, чем для горной тропы, быстро привлекли ваше внимание. В руках он держал деревянную каравеллу. Что это, детская игрушка? Или модель корабля, на котором он плавал? Вы не могли разобрать деталей из-за возраста истукана — изъеденное жучками дерево давно заплесневело. Пожалуй, это изображение было здесь одним из самых старых.', 'end', NULL, NULL, 'Только если у вас нет части 3 достижения «Путники из прошлого».', 'Получите часть 3 достижения «Путники из прошлого».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (723, 319, 3, 'choice', 'Поставить свечку слепому оруженосцу. Уже само то, что оруженосцем у этого рыцаря стала женщина, было чем-то неслыханным как на Родине, так и на Авалоне. Но помимо этого, её глаза были закрыты повязкой, и всё же она сжимала в руках двуручный меч. Вы могли только гадать, кто же она и что побудило её отправиться в путь…', 'end', NULL, NULL, 'Только если у вас нет части 4 достижения «Путники из прошлого».', 'Получите часть 4 достижения «Путники из прошлого».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (724, 319, 4, 'choice', 'Уйти. Вы выбросили бесполезную свечку и ушли.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
