INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (728, 321, 2, 'condition', 'В противном случае.', 'end', NULL, NULL, NULL, 'Однако, пока ваш новый союзник был всё ещё с вами, отправляться туда было нельзя. Вернитесь к этому позже.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
