INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (729, 322, 0, 'condition', 'Если в этой локации есть хотя бы 1 @LightTT@.', 'end', NULL, NULL, NULL, 'Эта область всё ещё слишком опасна.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (730, 322, 1, 'condition', 'Если вы победили.', 'end', NULL, NULL, NULL, 'Получите 2 магии.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
