INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (769, 342, 0, 'choice', 'Попросить о помощи и исцелении. Храмы в отдалённых краях часто помогают путникам, хотя именно в этом храме вы не были уверены.', 'verse', 20, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (770, 342, 1, 'choice', 'Спросить про жрицу, которая починила путеводный камень на перевале Короля. Казалось, с тех пор прошло много лет. Но вы до сих пор помнили, как она швырнула о разбитый камень странный сосуд — и камень магическим образом стал как новый.', 'verse', 1, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (771, 342, 2, 'choice', 'Сообщить об итогах вашей миссии.', 'verse', 7, NULL, 'Нужны части 1 и 2 достижения «Путь Венедии».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (772, 342, 3, 'choice', 'Спросить про Чернобога. Зачем служить злому богу?', 'verse', 5, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (773, 342, 4, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
