INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (774, 343, 0, 'choice', 'Продолжить.', 'verse', 2, NULL, NULL, 'Поздравляем! Вы освоили новое действие боя или дипломатии. Возьмите секретные карты 107 (карта боя «Чёрная свеча») и 112 (карта дипломатии «Чёрная свеча»). Выберите одну из них и замешайте в соответствующую колоду. Уберите другую карту из игры.  Элган получает 1 опыт.  Получите часть 9 достижения «Заготовки».', NULL, FALSE, NULL, NULL, NULL);
