INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (886, 393, 0, 'choice', '1.', 'end', NULL, NULL, NULL, 'Пока вы были заняты рыбалкой, с гор спустился древний зверь, жаждущий утолить голод.  Найдите карту встречи «Искажённый белый медведь» (зелёная, сложность 4) и проведите её. Затем исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (887, 393, 1, 'choice', '2.', 'end', NULL, NULL, NULL, 'На пойманную вами рыбу налетела стая голодных кричаек. Эти птицы никогда не терпели конкурентов.  Найдите карту встречи «Стая кричаек» (зелёная, сложность 3) и проведите её. Затем исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (888, 393, 2, 'choice', '3.', 'end', NULL, NULL, NULL, 'Вы почти ничего не поймали.  Получите 1 еду.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (889, 393, 3, 'choice', '4—6.', 'end', NULL, NULL, NULL, 'Быстрая речка оказалась полна идущей на нерест бронь-форели.  Получите столько еды, сколько у вас очков @Aggression@. Поместите в эту локацию 1 @DarkTT@.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
