INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (944, 420, 2, 'choice', '2 @Energy@ Исследовать близлежащие острова архипелага.', 'verse', 4, NULL, 'Только если в этой локации нет @LightTT@, а у вас нет ни одной части достижения «Время идёт» для текущей главы. Потратьте 1 золото.', NULL, NULL, FALSE, NULL, NULL, NULL);
