INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (950, 421, 2, 'choice', 'Спросить, где найти члена Круга, который мог бы за вас поручиться.', 'verse', 11, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
