INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (953, 422, 1, 'condition', 'Если вы победили.', 'verse', 5, NULL, NULL, 'Получите часть 6 достижения «Кто не рискует».', NULL, FALSE, NULL, NULL, NULL);
