INSERT INTO verses (id, location_id, display_number) VALUES (423, 33, 3);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (955, 423, 0, 'choice', 'Согласиться и вытянуть одну из нитей судьбы.', 'verse', 12, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (956, 423, 1, 'choice', 'Спросить, не причинит ли это какого-нибудь вреда.', 'verse', 10, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (957, 423, 2, 'choice', 'Отказаться. «Ты к нам ещё вернёшься, — рассмеялись они. — Это уже воткано в полотно».', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (424, 33, 4);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (958, 424, 0, 'choice', '1.', 'end', NULL, NULL, NULL, 'Вы нашли тихий островок с великолепными видами и немного отдохнули на нём, прежде чем отправиться обратно.   Получите 1 @Energy@.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (959, 424, 1, 'choice', '2.', 'end', NULL, NULL, NULL, 'Вы причалили к унылому каменистому островку, на котором ничего не нашли.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (960, 424, 2, 'choice', '3.', 'end', NULL, NULL, NULL, 'Вы причалили к каменистому берегу, на котором маячил остов потерпевшего крушение корабля. В трюме вы нашли кое‑какие ценности.  Получите 2 золота.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (961, 424, 3, 'choice', '4.', 'end', NULL, NULL, NULL, 'Вы нашли крошечный островок, весь покрытый гнёздами морских птиц.  Получите 2 еды.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (962, 424, 4, 'choice', '5.', 'end', NULL, NULL, NULL, 'Вы причалили к островку с давно заброшенной хижиной, в которой нашли полезный предмет.  Получите 1 предмет В.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (963, 424, 5, 'choice', '≥6.', 'end', NULL, NULL, NULL, 'На вашу лодку напало морское чудовище!  Найдите секретную карту встречи 243 «Акула-гоблин» (фиолетовая, сложность 3) и проведите её. Затем исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (425, 33, 5);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (964, 425, 0, 'choice', 'Попросить их призвать бурю. Вам было нужно, чтобы волны опять нанесли янтарь на северные берега.', 'verse', 3, NULL, 'Только если вы проходите главу 7А, часть 1.', 'Поместите в эту локацию 1 @QuestToken@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (965, 425, 1, 'choice', 'Попросить их призвать прекрасную погоду. Вам был нужен ясный денёк — чтобы закончить расследование или просто немного отдохнуть.', 'verse', 3, NULL, NULL, 'Поместите в эту локацию 1 красный маркер.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (966, 425, 2, 'choice', 'Спросить, могут ли они добавить в полотно судьбы поражение янтарной царицы Венеды.', 'verse', 8, NULL, 'Только если у вас нет части 10 достижения «Путь Венедии».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (967, 425, 3, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
