INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (969, 426, 1, 'choice', 'Заплатить ему.', 'verse', 7, NULL, 'Потратьте в общей сложности 3 золота и/или магии за персонажа.', NULL, NULL, FALSE, 'В противном случае.', NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (970, 426, 2, 'choice', 'Убедить его, что он должен рассказать вам всё просто так.', 'verse', 7, NULL, 'Нужно хотя бы 3 очка @Practicality@.', NULL, NULL, FALSE, 'В противном случае.', NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (971, 426, 3, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, 'В противном случае.', NULL, NULL);
