INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (994, 439, 1, 'choice', '1 @Energy@ Найти работу. Это был зажиточный край, и найти здесь работу казалось несложным.', 'verse', 18, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
