INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1002, 443, 0, 'choice', '1 @Energy@ Расспросить влинчан обо всём, что связано со случившимся.', 'verse', 6, NULL, 'Нужна часть 7 достижения «Слухи и сплетни».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1003, 443, 1, 'choice', '1 @Energy@ Найти Андро.', 'verse', 12, NULL, 'Нужна часть 7 достижения «Слухи и сплетни».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1004, 443, 2, 'choice', '1 @Energy@ Поторговать с ними.', 'verse', 25, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1005, 443, 3, 'choice', 'Расспросить об их убеждениях. Что они думают про янтарную царицу? Вдруг получится убедить их встать на сторону Жеремья?', 'verse', 5, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1006, 443, 4, 'choice', 'Спросить, почему они не вышли на покос.', 'verse', 9, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1007, 443, 5, 'choice', 'Предъявить результаты своего расследования.', 'verse', 7, NULL, 'Нужна часть 2 достижения «Горькая правда». Только если у вас нет части 5 достижения «Народный герой».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1008, 443, 6, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
