INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1010, 445, 0, 'choice', '1—2.', 'end', NULL, NULL, NULL, 'Ваши бесконечные расспросы настроили жителей Влинского против вас.   Найдите карту встречи «Сокрытый народ» (синяя, сложность 3) и проведите её. Вне зависимости от её итога исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1011, 445, 1, 'choice', '3—6.', 'end', NULL, NULL, NULL, 'Расспросы были долгими и бесплодными. Вы ушли ни с чем.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1012, 445, 2, 'choice', '≥7.', 'verse', 11, NULL, NULL, 'Вы узнали кое-что полезное!', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (446, 34, 7);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1013, 446, 0, 'choice', 'Сказать им, что вы обошли поля и никакой полудницы там нет. Андро, скорее всего, перегрелся на солнце, и ему померещилось. Можно спокойно возвращаться на работу.', 'verse', 1, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1014, 446, 1, 'choice', 'Сказать им, что в полях скрывается Младена. Это её Андро принял за полудницу. Можно спокойно возвращаться на работу.', 'verse', 3, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1015, 446, 2, 'choice', 'Сказать им, что полудница и в самом деле живёт в полях, но появляется только рядом с одиноким деревом. Если избегать этого места, можно спокойно возвращаться на работу.', 'verse', 10, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
