INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1017, 447, 1, 'choice', 'С боем прорваться к его барину.', 'verse', 23, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1018, 447, 2, 'choice', 'Сказать ему, что вы новый барин этого поместья, и показать грамоту.', 'verse', 28, NULL, 'Нужен Осберт.', NULL, NULL, FALSE, NULL, NULL, NULL);
