INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1175, 523, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (524, 37, 3);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1176, 524, 0, 'condition', 'Если в этой локации есть @QuestToken@.', 'verse', 11, NULL, NULL, 'Уберите @QuestToken@ из этой локации.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1177, 524, 1, 'choice', 'Подстрелить постового издалека, а затем взобраться на башню по цепи.', 'verse', 5, NULL, 'Нужна Гердвин.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1178, 524, 2, 'choice', 'Бесшумно проскользнуть к крепости по волнам.', 'verse', 7, NULL, 'Нужна Юнис в искажённой форме.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1179, 524, 3, 'choice', 'Нырнуть и проплыть ко входу в крепость под водой.', 'verse', 7, NULL, 'Нужна Юнис не в искажённой форме.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1180, 524, 4, 'choice', 'Плыть ко входу в крепость, стараясь по возможности держаться под водой. Ледяные волны залива быстро истощат ваши силы, и из-за одного неверного движения может подняться тревога.', 'verse', 9, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1181, 524, 5, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (525, 37, 4);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1182, 525, 0, 'choice', 'Заплатить стражникам столько, сколько попросят.', 'end', NULL, NULL, 'Потратьте в общей сложности 4 золота и/или магии за персонажа.', 'Поместите в эту локацию 1 @QuestToken@.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1183, 525, 1, 'choice', 'Уйти. Проще будет опустить цепь самостоятельно.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (526, 37, 5);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1184, 526, 0, 'choice', 'Продолжить.', 'verse', 11, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (527, 37, 6);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1185, 527, 0, 'choice', 'Если вы сбросили все @DarkTT@.', 'verse', 13, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1186, 527, 1, 'choice', 'Если все члены команды отступили или при смерти.', 'verse', 18, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (528, 37, 7);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1187, 528, 0, 'choice', 'Продолжить.', 'verse', 11, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (529, 37, 8);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1188, 529, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (530, 37, 9);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1189, 530, 0, 'choice', 'Продолжить.', 'verse', 14, NULL, NULL, 'Поместите в эту локацию 1 @QuestToken@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (531, 37, 10);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1190, 531, 0, 'choice', 'Если вы победили.', 'verse', 17, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1191, 531, 1, 'choice', 'В противном случае.', 'verse', 18, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (532, 37, 11);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1192, 532, 0, 'condition', 'Если вы проходите главу 9Б.', 'verse', 21, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1193, 532, 1, 'choice', 'Броситься на подмогу туда, где больше всего сражающихся. Вы окажетесь в самом центре ожесточённой битвы.', 'verse', 6, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1194, 532, 2, 'choice', 'Выбрать противника с умом. Вы нападёте на одного из командиров врага и сосредоточитесь на том, чтобы обезвредить его.', 'verse', 10, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1195, 532, 3, 'choice', 'Призвать на помощь горожан. Жители города столпились с копьями и кистенями в руках на безопасном расстоянии от битвы. Может, они согласятся выступить за Варегарда?', 'verse', 12, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1196, 532, 4, 'choice', 'Отойти назад и использовать магию. Вы не собирались рисковать своей шкурой, но ваших магических способностей должно было быть достаточно.', 'verse', 16, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1197, 532, 5, 'choice', 'Не делать ничего. Вы уже сделали всё, что от вас требовалось. Если морские разбойники не смогут отбить город, это будет не ваша вина.', 'verse', 18, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (533, 37, 12);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1198, 533, 0, 'choice', '1—2.', 'verse', 18, NULL, NULL, 'Ваше вмешательство разозлило их, и они бросились в бой на стороне людей Венеды.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1199, 533, 1, 'choice', '3—4.', 'verse', 11, NULL, NULL, 'Вы не смогли их убедить. Но хотя бы они не пошли сражаться на стороне врага…', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1200, 533, 2, 'choice', '≥5.', 'verse', 17, NULL, NULL, 'Горожане решили использовать эту возможность, чтобы сбросить иго Венеды. Они бросились вперёд, и чаша весов быстро склонилась в сторону Варегарда.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (534, 37, 13);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1201, 534, 0, 'choice', 'Меньше чем @Cube@ за члена команды.', 'verse', 18, NULL, NULL, 'Вам не удалось значительно повлиять на ход битвы.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1202, 534, 1, 'choice', 'Столько же или больше чем @Cube@ за члена команды, но меньше чем @Cube2@ за члена команды.', 'verse', 17, NULL, NULL, 'Вы внесли свою лепту, и, возможно, именно благодаря вам морские разбойники остались в живых. За ваши усилия вы получили долю в добыче.  Получите 2 золота.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1203, 534, 2, 'choice', 'Столько же или больше чем @Cube2@ за члена команды.', 'verse', 17, NULL, NULL, 'Эта победа стала в основном вашей заслугой. Морские разбойники принялись чествовать вас за победу. Вы получили право первыми выбрать добычу.  Каждый член команды теряет 1 @Terror@. Получите 4 золота.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (535, 37, 14);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1204, 535, 0, 'condition', 'Если в этой локации есть хотя бы 6 @QuestToken@.', 'verse', 15, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1205, 535, 1, 'condition', 'Если в этой локации есть хотя бы 4 @QuestToken@.', 'verse', 22, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1206, 535, 2, 'choice', '1—2.', 'verse', 22, NULL, NULL, 'Стражник морской башни вас заметил!', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1207, 535, 3, 'choice', '3—4.', 'verse', 14, NULL, NULL, 'Сражаясь с холодными волнами, вы проплыли совсем немного, прежде чем вам пришлось вынырнуть от нехватки воздуха.  Поместите в эту локацию 1 @QuestToken@.   Вернитесь к началу этой строфы.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1208, 535, 4, 'choice', '5—6.', 'verse', 14, NULL, NULL, 'Плыть было тяжело и утомительно, но вы неплохо продвинулись вперёд.   Поместите в эту локацию 2 @QuestToken@.   Вернитесь к началу этой строфы.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1209, 535, 5, 'choice', '≥7.', 'verse', 14, NULL, NULL, 'Вы рассекали тёмные волны как рыба и преодолели бо́льшую часть пути.  Поместите в эту локацию 3 @QuestToken@.   Вернитесь к началу этой строфы.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (536, 37, 15);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1210, 536, 0, 'choice', 'Продолжить.', 'verse', 11, NULL, NULL, 'Уберите все @DarkTT@ и @QuestToken@ из этой локации.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (537, 37, 16);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1211, 537, 0, 'choice', '1—3.', 'verse', 18, NULL, NULL, 'Ваши жалкие попытки помочь только внесли смуту и помешали людям Варегарда.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1212, 537, 1, 'choice', '4—7.', 'verse', 11, NULL, NULL, 'Заклинания никак не повлияли на ход битвы.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1213, 537, 2, 'choice', '≥8.', 'verse', 17, NULL, NULL, 'Ваша боевая магия повернула ход битвы в пользу Варегарда и его людей.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (538, 37, 17);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1214, 538, 0, 'choice', 'Если у вас есть хотя бы три части достижения «Союз Чернолесья».', 'cross_location', 980, 1001, NULL, 'Каждый персонаж получает 1 опыт.  Возьмите 4 предмета В. Оставьте себе 2 из них и сбросьте остальные.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1215, 538, 1, 'choice', 'В противном случае.', 'end', NULL, NULL, NULL, 'Каждый персонаж получает 1 опыт.  Возьмите 4 предмета В. Оставьте себе 2 из них и сбросьте остальные.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (539, 37, 18);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1216, 539, 0, 'condition', 'Если вы проходите главу 8А, часть 1 или 3..', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1217, 539, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, 'В противном случае.', NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (540, 37, 19);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1218, 540, 0, 'choice', '0—5.', 'end', NULL, NULL, NULL, 'Потратив уйму времени, вы решили, что сейчас на рынке нет ничего особо ценного.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1219, 540, 1, 'choice', '≥6.', 'end', NULL, NULL, NULL, 'Вы нашли редкую вещь, и задёшево!  Поместите 1 @LightTT@ в эту локацию.  Возьмите 1 случайный предмет Д. Можете купить этот предмет за 5 золота. Если вы купили его, получите одну часть достижения «Ограниченный запас».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (541, 37, 20);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1220, 541, 0, 'condition', 'Продолжить.', 'cross_location', 639, 1001, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
