INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1221, 542, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (543, 37, 22);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1222, 543, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Уберите все @DarkTT@ и @QuestToken@ из этой локации.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
