INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1223, 544, 0, 'condition', 'Если вы проходите главу 9Б.', 'verse', 8, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1224, 544, 1, 'choice', '2 @Energy@ Провести ритуал.', 'verse', 3, NULL, 'Нужна глава 8А, часть 4.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1225, 544, 2, 'choice', '1 @Energy@ Посетить палаты Венеды.', 'verse', 2, NULL, 'Только если у вас нет части 9 достижения «Бессердечность».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1226, 544, 3, 'choice', '1 @Energy@ Купить редкие товары.', 'verse', 6, NULL, 'Только если в этой локации нет @LightTT@.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1227, 544, 4, 'choice', 'Подойти к месту казни.', 'verse', 1, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1228, 544, 5, 'choice', 'Разузнать о Железной дружине.', 'verse', 4, NULL, 'Нужна Гердвин.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1229, 544, 6, 'choice', 'Поторговать.', 'verse', 5, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
