INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1555, 674, 1, 'choice', 'Вы заметили одинокую фигуру под сенью хижины, построенной из выброшенной на берег древесины…', 'end', NULL, NULL, 'Нужна глава 7Б, часть 1—3, и часть 1 достижения «Празднество». Только если у вас нет части 1 достижения «Изолют».', NULL, NULL, FALSE, NULL, NULL, '[{"type": "condition", "text": "Если вы не хотите, чтобы Изолют присоединилась к вам.", "target": "end", "result": "Исследование окончено."}, {"type": "condition", "text": "Если вы хотите, чтобы она присоединилась к вам.", "target": "end", "result": "Получите часть 1 достижения «Изолют» и часть 4 достижения «Спутники».  Получите секретную карту 307 и ознакомьтесь с правилами на ней.  Исследование окончено."}]'::jsonb);
