INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1684, 730, 1, 'choice', '1 @Energy@ Бросить останки в Багровую колыбель. По слухам, если что-нибудь отдать Колыбели, она будет обязана отдать что-нибудь в ответ.', 'verse', 12, NULL, 'Нужна карта секрета 13.', NULL, NULL, FALSE, NULL, NULL, NULL);
