INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1699, 734, 1, 'choice', 'Накормить субстанциями Ненасытность. Это пойдёт вразрез со всеми вашими предыдущими усилиями. Колыбель ослабеет навсегда, а ваша миссия может окончиться провалом, но вам хотя бы не придётся идти на сделку с этой сущностью.', 'cross_location', 1151, 1001, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (735, 56, 6);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1700, 735, 0, 'condition', 'Нажмите сюда, если хотите увидеть подсказку.', 'verse', 6, NULL, NULL, 'Берите от Колыбели всё, что можете взять, не оставаясь в долгу перед ней.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1701, 735, 1, 'choice', 'Попросить излечения и восстановления.', 'end', NULL, NULL, NULL, 'Получите две части достижения «Долг». Затем каждый персонаж получает 3 @Health@ и теряет 2 @Terror@.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1702, 735, 2, 'choice', 'Попросить еды.', 'end', NULL, NULL, NULL, 'Получите 3 еды и одну часть достижения «Долг».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1703, 735, 3, 'choice', 'Попросить магии.', 'end', NULL, NULL, NULL, 'Получите 2 магии и одну часть достижения «Долг».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1704, 735, 4, 'choice', 'Попросить полезного снаряжения.', 'end', NULL, NULL, NULL, 'Получите 1 предмет Д и одну часть достижения «Долг».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1705, 735, 5, 'choice', 'Попросить дивосвечу.', 'end', NULL, NULL, NULL, 'Получите одноразовый предмет «Дивосвеча» и одну часть достижения «Долг».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1706, 735, 6, 'choice', 'Попросить путеводный камень.', 'verse', 9, NULL, NULL, 'Получите одну часть достижения «Долг».', NULL, FALSE, NULL, NULL, NULL);
