INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1718, 739, 3, 'choice', 'Попросить Колыбель о даре. Она могла снабдить вас всем необходимым, что только можно было представить.', 'verse', 6, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1719, 739, 4, 'choice', 'Принести Колыбели дар. Оставаться в долгу перед этим пугающим местом вам было не по себе.', 'verse', 4, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
