INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1866, 798, 0, 'condition', 'Если вы играете за Элгана и у вас нет части 5 достижения «Заготовки».', 'verse', 4, NULL, NULL, 'Среди записей об опасных древних культах вы нашли детальное описание благовония, которое делает собеседников склонными соглашаться на ваши уговоры. Наверняка у вас получится его воссоздать.  Поздравляем! Вы освоили новое действие дипломатии. Получите секретную карту 111 (карта дипломатии «Завораживающая свеча») и замешайте её в колоду дипломатии Элгана. Получите часть 5 достижения «Заготовки».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1867, 798, 1, 'condition', 'Если вы играете за Гердвин и у вас нет части 6 достижения «Заготовки».', 'verse', 4, NULL, NULL, 'Вы с головой погрузились в летописи былых войн, полные грандиозных и вдохновляющих цитат полководцев. Это позволило вам получше узнать, как уверенно убеждать окружающих в непростых обстоятельствах.  Поздравляем! Вы освоили новое действие дипломатии. Получите секретную карту 121 (карта дипломатии «Категоричные приказы») и замешайте её в колоду дипломатии Гердвин. Получите часть 6 достижения «Заготовки».', NULL, FALSE, NULL, NULL, NULL);
