INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1870, 800, 0, 'condition', 'Если вы играете за Осберта и у вас нет части 7 достижения «Заготовки».', 'verse', 6, NULL, NULL, 'Неподалёку от тренирующихся рыцарей вы встретили королевских разведчиков Лотиана, обучавшихся мастерству шпионажа и хитроумным уловкам. Несмотря на их насмешки, их старый учитель признал ваш очевидный талант и решил научить вас нескольким полезным приёмам.  Поздравляем! Вы освоили новое действие боя. Получите секретную карту 136 (карта боя «Поживиться») и замешайте её в колоду боя Осберта. Получите часть 7 достижения «Заготовки».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1871, 800, 1, 'condition', 'Если вы играете за Юнис и у вас нет части 8 достижения «Заготовки».', 'verse', 6, NULL, NULL, 'Сойтись в тренировочном бою с настоящими рыцарями-людьми — это было то, о чём вы всегда мечтали. И вы, и они обзавелись несколькими впечатляющими синяками и освоили пару новых приёмов. А бдительная защитная стойка, которую вы переняли у них, когда-нибудь может спасти вам жизнь!  Поздравляем! Вы освоили новое действие боя. Получите секретную карту 126 (карта боя «Прицельная оборона») и замешайте её в колоду боя Юнис. Получите часть 8 достижения «Заготовки».', NULL, FALSE, NULL, NULL, NULL);
