INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (1927, 824, 3, 'choice', '1 @Energy@ Убедить какого-нибудь незнакомца стать «сладостным святым».', 'end', NULL, NULL, 'Нужна часть 7 достижения «Дипломат».', NULL, NULL, FALSE, NULL, NULL, '[{"type": "condition", "text": "Если у вас есть часть 6 достижения «Бессердечность».", "target": {"verse": 5}}, {"type": "choice", "text": "Продолжить.", "target": "end", "result": "Поместите 2 @LightTT@ в локацию 129.  Получите часть 6 достижения «Бессердечность».  Исследование окончено."}]'::jsonb);
