INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2137, 921, 0, 'choice', 'Согласиться, при условии что он перестанет грабить южан. Вы откажетесь от награды, но южане наконец будут в безопасности.', 'verse', 60, NULL, NULL, 'Поместите в эту локацию 1 @QuestToken@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2138, 921, 1, 'choice', 'Согласиться, при условии что он всё-таки заплатит вам обещанную «награду».', 'verse', 60, NULL, NULL, 'Получите 2 золота за персонажа.  Возьмите 4 предмета Б, оставьте себе 2 из них и сбросьте остальные.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2139, 921, 2, 'choice', 'Согласиться и сообщить ему, где находится сокровищница Сурлузы, чтобы он перестал грабить южан. Вы получите свою награду и спасёте южан, но сокровища станут предметом спора, что непременно разгневает королевскую семью Лотиана.', 'verse', 60, NULL, NULL, 'Поместите в эту локацию 2 @QuestToken@.  Получите 2 золота за персонажа.  Возьмите 4 предмета Б, оставьте себе 2 из них и сбросьте остальные.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2140, 921, 3, 'choice', 'Отказаться. Вопрос о том, кто дальше будет главой дружины, решится здесь и сейчас в поединке.', 'verse', 81, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
