INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2168, 938, 1, 'choice', 'Воспротивиться клейму и найти способ избавиться от него. Ваша судьба принадлежит только вам! А искатели и их проклятье как-нибудь без вас обойдутся!', 'verse', 370, NULL, NULL, 'Уберите из игры карту секрета 8 и получите карту секрета 9.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2169, 938, 2, 'choice', 'Подчиниться клейму и принять свою миссию. Найти Короля-на-Востоке — давняя мечта многих героев Западного Авалона. И если верить искателям, именно у вас есть шанс её наконец-то исполнить.', 'verse', 370, NULL, NULL, 'Уберите из игры карту секрета 8 и получите карту секрета 6.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (939, 75, 52);
