INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2182, 947, 0, 'choice', 'Спасти соратницу. Вы схватились за оружие и бросились на помощь старой подруге. Шум перебудит всех в лагере, приведя к жестокой схватке между сторонниками Рольфа и вашими бывшими соратниками.', 'verse', 81, NULL, NULL, 'Получите часть 3 достижения «Личные дела».  Если в этой локации есть @QuestToken@, сбросьте их.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2183, 947, 1, 'choice', 'Отвернуться и отправиться прочь. Железная дружина осталась для вас в прошлом, и незачем за неё цепляться. Вам больше ничего от них не надо.', 'verse', 66, NULL, 'Важно: это завершит личную историю Гердвин здесь и сейчас.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (948, 75, 61);
