INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2188, 950, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 7 достижения «Что плохо лежит».  Получите 3 золота и 1 предмет Д.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
