INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2189, 951, 0, 'choice', 'Сказать, что править должен Аэд, а то, что в нём самом нет королевской крови, необходимо сохранить в тайне.', 'verse', 374, NULL, 'Если у вас нет части 5 достижения «Королевские похороны», вернитесь в главное меню и перейдите к строфе секрета 379.   Если у вас есть часть 5 достижения «Королевские похороны», нажмите «Принять».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2190, 951, 1, 'choice', 'Сказать, что править должны Скорбные близнецы, так как они королевской крови.', 'verse', 369, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2191, 951, 2, 'choice', 'Сказать, что есть ещё один наследник — дочь Калеки.', 'verse', 361, NULL, 'Нужна часть 1 или часть 4 достижения «Семейные тайны».', NULL, NULL, FALSE, NULL, NULL, NULL);
