INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2196, 954, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Гердвин сделала окончательный выбор в своей личной истории. Вы ознакомитесь с её развязкой, когда завершите игру.  o Получите часть 1 достижения «Конец пути» и часть 5 достижения «Личные дела».  o Гердвин получает 1 опыт, 4 золота и 2 предмета Б.  o Гердвин получает секретную карту 119 (карта боя «Прощальный выстрел») и секретную карту 124 (карта дипломатии «Непреклонность»). Замешайте их в соответствующие колоды.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
