INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2231, 976, 0, 'choice', 'Продолжить.', 'verse', 92, NULL, NULL, 'Каждый член команды суммирует значения своих @Energy@, @Health@ и @Terror@, затем опускает свои @Energy@, @Health@ и @Terror@ до 0 и выставляет на этих трёх шкалах любые значения таким образом, чтобы их сумма была равна прежде высчитанной.  Важно: по-прежнему учитывайте все ограничения (такие как эффект маркера @Health@ или длина шкалы).  Получите часть 4 достижения «Трофеи искаженья».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (977, 75, 90);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2232, 977, 0, 'choice', 'Посоветовать и дальше собирать долги с южан. Набеги продолжатся, но это даст возможность ослабленной дружине выжить.', 'verse', 93, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2233, 977, 1, 'choice', 'Посоветовать оставить южан в покое и выживать иначе. Железная дружина ещё больше ослабнет, зато для южан наступит мир.', 'verse', 93, NULL, NULL, 'Получите часть 6 достижения «Великие деяния» и часть 4 достижения «Личные дела».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2234, 977, 2, 'choice', 'Сообщить им, где находится сокровищница Сурлузы, чтобы они перестали грабить южан. Вы спасёте южан, но сокровища станут предметом спора, что непременно разгневает королевскую семью Лотиана.', 'verse', 93, NULL, NULL, 'Получите часть 4 достижения «Осведомитель» и часть 6 достижения «Великие деяния».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2235, 977, 3, 'choice', 'Посоветовать им отправить посланников к королевской семье Лотиана за причитающимся долгом. Недавно в Лотиане сменилась власть. Можно убедить преемника короля Лота сдержать давно данное слово.', 'verse', 93, NULL, 'Нужны хотя бы 2 очка @Practicality@ и часть 1 достижения «Королевские похороны».', 'Получите часть 6 достижения «Великие деяния».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (978, 75, 91);
INSERT INTO verses (id, location_id, display_number) VALUES (979, 75, 92);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2236, 979, 0, 'choice', 'Отправиться туда немедленно.', 'verse', 95, NULL, 'Это закончит ваш день.', 'Переместите всех персонажей и спутников в локацию 110. Если она лежит @Clear@ стороной вверх, не применяйте её @Thunder@ эффект.  Каждый персонаж теряет всю свою @Energy@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2237, 979, 1, 'choice', 'Остаться здесь. У вас остались незаконченные дела к югу от перевала Короля.', 'verse', 95, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (980, 75, 93);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2238, 980, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 5 достижения «Личные дела».  Получите 2 золота за персонажа. Возьмите 4 предмета Б, оставьте себе 2 из них и сбросьте остальные.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
