INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2255, 985, 0, 'condition', 'Нажмите сюда, если хотите увидеть решение.', 'verse', 98, NULL, NULL, 'Приходить на Угрюмый хребет будет опасно. Убедитесь, что вы здоровы и хорошо снаряжены, прежде чем входить в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
