INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2257, 986, 0, 'condition', 'Нажмите сюда, если хотите увидеть решение.', 'verse', 99, NULL, NULL, 'Когда вы придёте в Колонию-Мариану (восток), ваша глава завершится. Если вы хотите разобраться с незаконченными делами, сделайте это, прежде чем вернуться к Октавии.', NULL, FALSE, NULL, NULL, NULL);
