INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2261, 989, 0, 'choice', 'Позволить стражникам схватить её. Коронация пройдёт, как и было запланировано.', 'verse', 171, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2262, 989, 1, 'choice', 'Поддержать её притязания на трон. С доказательствами на руках вы вполне способны возвести на трон юную Эльдриду.', 'verse', 194, NULL, 'Нужна часть 4 или 5 достижения «Семейные тайны».', NULL, NULL, FALSE, NULL, NULL, NULL);
