INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2263, 990, 0, 'condition', 'Нажмите сюда, если хотите увидеть решение.', 'verse', 103, NULL, NULL, 'Если вы хотите выполнить миссию Капреллиды, отправьтесь в Вороний приют (161).  Если вы хотите самостоятельно добыть информацию:  o Отправьтесь к Одинокому шпилю и войдите в башню.  o Отправьтесь в Вороний приют, когда карта этой локации лежит искажённой стороной вверх.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2264, 990, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
