INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2321, 1023, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 2 достижения «Выступления».  Осберт получает 1 опыт и теряет 1 @Terror@.  Поздравляем! Вы освоили новое действие дипломатии. Получите секретную карту 140 (карта дипломатии «Поток вдохновения») и замешайте её в колоду дипломатии Осберта.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
