INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2323, 1024, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите 1 золото, 1 магию и одноразовый предмет «Дивосвеча» (если он доступен).   Получите часть 3 достижения «Диковинки».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
