INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2325, 1026, 0, 'condition', 'Если у вас есть карта секрета 9.', 'end', NULL, NULL, NULL, 'Вы лишили труп существа его силы, и ваше клеймо поглотило её, словно энергию путеводного камня. Потом вы от злости пнули останки. Искатели сломали вашу жизнь своим проклятием, и теперь вы мечтали отомстить каждому из них!  Получите 1 магию и потеряйте 1 @Terror@.  Продолжайте игру.', NULL, FALSE, NULL, NULL, NULL);
