INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2345, 1038, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 1 достижения «Песни Авалона» и часть 1 достижения «Народный герой».  Каждый персонаж получает 1 опыт.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
