INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2346, 1039, 0, 'choice', '0—2.', 'end', NULL, NULL, NULL, 'Галлюцинации прекратились, и горожане пришли в чувство почти без последствий. В знак извинений они осыпали вас дарами.  Каждый член команды получает 3 еды, 2 золота и теряет 2 @Terror@.  Эта встреча окончена.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2347, 1039, 1, 'choice', '3—5.', 'end', NULL, NULL, NULL, 'Галлюцинации прекратились. Увы, защищая себя, вы поранили нескольких горожан. Они всё равно извинились и предложили компенсацию.  Каждый член команды получает 2 еды, 1 золото и теряет 1 @Terror@.  Эта встреча окончена.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2348, 1039, 2, 'choice', '≥6.', 'end', NULL, NULL, NULL, 'Галлюцинации прекратились. Жестоко избитые вами горожане недовольно смотрели на вас. Кто-то из старших извинился и передал небольшой подарок.  Получите 2 еды и 2 золота.  Эта встреча окончена.', NULL, FALSE, NULL, NULL, NULL);
