INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2414, 1075, 0, 'choice', 'Осмотреть товары. Невиданные товары красовались на прилавках.', 'verse', 7, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2415, 1075, 1, 'choice', 'Попробовать что-то стащить. Местные спокойны и не ждут подвоха. Наверняка вы сможете обернуть это себе на пользу!', 'verse', 120, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2416, 1075, 2, 'choice', 'Пойти дальше по главной дороге к городским воротам. Как далеко простирается это отражение?', 'verse', 33, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2417, 1075, 3, 'choice', 'Спросить дорогу. Местные казались дружелюбными, они наверняка помогут.', 'verse', 61, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2418, 1075, 4, 'choice', 'Оставить отражение. Холодные объятия чёрных вод терпеливо ждали вас.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1076, 75, 190);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2419, 1076, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'o Каждый персонаж получает 1 опыт.  o Сбросьте колоду событий и все активные события.  o Каждый персонаж может потратить опыт, чтобы повысить свои характеристики, получить новые навыки или добавить новые карты боя и дипломатии в свои колоды (см. «Характеристики и развитие персонажа» на с. 20 правил игры).  o Самое время сделать паузу! Либо сохраните игру, либо возьмите карту «Подготовка к главе 3» и следуйте её указаниям, чтобы начать новую главу.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
