INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2548, 1139, 2, 'choice', 'Рассказать родителям мальчика, как сделать так, чтобы волосы больше не отрастали.', 'verse', 266, NULL, NULL, 'Мать выглядела почти расстроенной, когда вы раскрыли тайну её сына, а мальчик расплакался. Но пути назад не было.  Каждый персонаж с хотя бы 1 очком @Empathy@ получает 1 @Terror@.', NULL, FALSE, NULL, NULL, NULL);
