INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2561, 1150, 0, 'condition', 'Нажмите сюда, если хотите увидеть подсказку.', 'verse', 264, NULL, NULL, 'Подсказка: Кендрик, учёный-призрак, — это персонаж-спутник, который сможет дать вам дополнительные сведения о локациях, в которых вы находитесь, или об активной миссии. Но нахождение рядом с ним грозит определёнными опасностями.', NULL, FALSE, NULL, NULL, NULL);
