INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2660, 1203, 0, 'condition', 'Если у вас есть часть 2 достижения «Великие деяния».', 'end', NULL, NULL, NULL, 'Врата безмолвствуют.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2661, 1203, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Переместите всех персонажей из локации 120 в локацию 119 (либо 119-Б).  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1204, 75, 318);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2662, 1204, 0, 'condition', 'Если у вас есть часть 6 достижения «Личные дела».', 'verse', 311, NULL, NULL, 'Собранные зацепки явно говорили о том, что ваша семья находилась в Фомории. Они попали в рабство или подвергались другой смертельной опасности, и вам нужно было найти их и убедиться, что им ничего не угрожало, — несмотря на то, как чудовищно вы теперь выглядели.  Поместите 1 красный маркер в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2663, 1204, 1, 'condition', 'Если у вас есть часть 2 достижения «Личные дела».', 'verse', 311, NULL, NULL, 'События в Лотиане настолько захватили вас, что вы так и не добрались до Верхнего города и не узнали, что стало с вашими родными. Теперь, когда искаженье исковеркало ваше тело, у вас оставалось совсем мало времени, чтобы с ними увидеться.  Поместите 1 красный маркер в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2664, 1204, 2, 'choice', 'Продолжить.', 'verse', 311, NULL, NULL, 'Поместите 1 красный маркер в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1205, 75, 319);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2665, 1205, 0, 'condition', 'Если у вас есть часть 1 достижения «Конец пути».', 'verse', 311, NULL, NULL, 'Вы, вероятно, были прокляты. Только вчера вы освободились от власти теней прошлого и открыли новую страницу в жизни. Но теперь, когда искаженье так исковеркало ваше тело, жизнь будто бы была кончена. Однако вы не сдавались. Вы готовы были бороться за свою жизнь, даже если ради этого придётся найти способ избавиться от клейма искателя.  Поместите 1 @QuestToken@ в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2666, 1205, 1, 'condition', 'Если у вас есть часть 4 достижения «Личные дела».', 'verse', 311, NULL, NULL, 'Вам предстояло отыскать Рольфа, который сбежал с казной, хроникой дружины и знаменем, которое вы так долго хранили. Теперь, когда искаженье изуродовало ваше тело, а клеймо искателя с каждым днём жглось всё сильнее, искать этого предателя будет нелегко. Но вы не собирались сдаваться.   Поместите 1 @QuestToken@ в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2667, 1205, 2, 'choice', 'Продолжить.', 'verse', 311, NULL, NULL, 'Поместите 1 @QuestToken@ в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1206, 75, 320);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2668, 1206, 0, 'choice', 'Продолжить.', 'verse', 314, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
