INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2671, 1209, 0, 'choice', 'Продолжить.', 'verse', 342, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1210, 75, 324);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2672, 1210, 0, 'condition', 'Если у вас есть часть 8 достижения «Небольшая услуга».', 'verse', 360, NULL, NULL, 'Не успела стража выдворить вас прочь, как вмешалась королева Ольфрида.  — Шериф, прекрати это немедленно! Я полностью доверяю этой особе. Выгони остальных, и пусть наш друг приступает к работе.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2673, 1210, 1, 'condition', 'Если у вас есть часть 6 достижения «Небольшая услуга».', 'verse', 360, NULL, NULL, 'Не успела стража выдворить вас прочь, как раздался пронзительный крик. Толпа расступилась, освобождая путь для близнецов в паланкине.  — Молчать! Всем молчать! Ты! Мы верим только тебе. / Во что бы то ни стало раскрой это чудовищное преступление.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2674, 1210, 2, 'condition', 'В противном случае.', 'verse', 427, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
