INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2725, 1234, 0, 'choice', 'Продолжить.', 'cross_location', 895, 1001, NULL, 'Поздравляем! Гердвин сделала окончательный выбор в своей личной истории. Вы ознакомитесь с её развязкой, когда завершите игру.  o Получите часть 1 достижения «Конец пути».  o Гердвин получает 3 опыта и теряет весь @Terror@.  o Гердвин получает секретную карту 119 (карта боя «Прощальный выстрел») и секретную карту 124 (карта дипломатии «Непреклонность») и замешивает их в соответствующие колоды.  o Каждый персонаж получает 2 @Health@ и теряет 2 @Terror@.', NULL, FALSE, NULL, NULL, NULL);
