INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2783, 1262, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Юнис достигла важной вехи в своей личной истории. Вы ознакомитесь с её развязкой, когда завершите игру.  o Получите часть 7 достижения «Конец пути».  o Юнис получает 3 опыта.  o Юнис получает секретную карту 129 (карта боя «Ведомая ненавистью») и секретную карту 134 (карта дипломатии «Сладкая месть») и замешивает их в соответствующие колоды.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
