INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2794, 1269, 1, 'condition', 'Если у вас есть часть 2 достижения «Семейные тайны».', 'verse', 396, NULL, NULL, 'Убийцей был кто-то из близких короля Лота. Преступник зашёл к нему в шатёр поздно ночью. Король не поднял тревогу и не позвал стражников. Они что-то обсуждали, потом убийца швырнул в короля браслет из фальшивого золота и поддельных бриллиантов, а затем задушил его.', NULL, FALSE, NULL, NULL, NULL);
