INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2800, 1273, 1, 'condition', 'Если у вас есть часть 2 достижения «Семейные тайны».', 'verse', 396, NULL, NULL, 'Убийцей был кто-то из близких королевы. Он застал её врасплох, когда Ольфрида изучала какой-то странный фолиант, и вырвал книгу у неё из рук. Какое-то время продолжалась ссора, но стражу никто не позвал. Наконец, убийца дважды ударил королеву фолиантом и убил её, оставив на месте преступления кусок железного переплёта.', NULL, FALSE, NULL, NULL, NULL);
