INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2801, 1274, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый член команды теряет 2 @Terror@.   Получите часть 6 достижения «Свобода».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
