INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (2803, 1275, 1, 'condition', 'Если у вас есть часть 2 достижения «Семейные тайны».', 'verse', 396, NULL, NULL, 'Убийцей был кто-то из близких Аэда: принц даже угостил его выдержанным лотианским вином. У преступника был как минимум один сообщник. На месте убийства нашли браслет из фальшивого золота и поддельных бриллиантов. Он выглядел так, будто его не так давно выкопали из земли.', NULL, FALSE, NULL, NULL, NULL);
