INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3085, 1431, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Найдите секретную карту встречи 205 «Жители Сурлузы» (зелёная). Поместите на эту карту 1 @QuestToken@ (+1 @QuestToken@ за члена команды). Затем проведите встречу.  Если на карте «Жители Сурлузы» не осталось @QuestToken@, вы побеждаете в этой встрече и получаете добычу. Вне зависимости от итога встречи исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
