INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3086, 1432, 0, 'condition', 'Нажмите сюда, если хотите увидеть подсказку.', 'verse', 546, NULL, NULL, 'Подсказка: ваша цель находится далеко, и по пути туда может многое случиться. Убедитесь, что у вас достаточно провизии и ресурсов, либо запаситесь ими по дороге.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3087, 1432, 1, 'condition', 'Нажмите сюда, если хотите увидеть подсказку.', 'verse', 546, NULL, 'Только если у вас есть синий светофильтр.', 'Подсказка:: теперь у вас есть синий осколок искажень-стекла, и в некоторых локациях, в которых вы уже побывали, вам стали доступны новые взаимодействия.', NULL, FALSE, NULL, NULL, NULL);
