INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3102, 1442, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Вы освоили новое действие боя. Получите секретную карту 118 (карта боя «Поставить ловушку») и замешайте её в колоду боя Гердвин.  Получите часть 3 достижения «Угнетатель» и часть 4 достижения «Случайные встречи».  Гердвин получает 1 опыт.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
