INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3116, 1448, 1, 'choice', 'Сесть на землю и подождать.', 'verse', 568, NULL, NULL, 'Поместите в эту локацию 1 @QuestToken@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1449, 75, 563);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3117, 1449, 0, 'condition', 'Нажмите сюда, если хотите увидеть подсказку.', 'verse', 563, NULL, NULL, 'Подсказка: янтарные существа происходят из незапамятных времён, и зародились они в полном ядовитых газов вулканическом климате задолго до того, как остров погрузился в океан. Сами по себе они предпочитают избегать конфликтов и прятаться, но под руководством вожака стаи готовы напасть на кого угодно, невзирая на последствия. Они избегают солнечного света и излишнего внимания, предпочитая оставаться в тени и, по возможности, в укрытии. Янтарные твари — засадные хищники, они затаиваются обычно в высоких и толстых ветвях крупных деревьев, откуда нападают на существ поменьше, чем они сами. Для поддержания жизни им также необходима богатая солями и минералами вода, желательно из недр земли.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3118, 1449, 1, 'condition', 'Если вы находитесь в локации 141-Б.', 'cross_location', 876, 1001, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3119, 1449, 2, 'condition', 'В противном случае.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
