INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3121, 1450, 1, 'condition', 'В противном случае.', 'verse', 568, NULL, NULL, 'С трудом, но янтарная тварь смогла подавить порыв и остаться на месте.', NULL, FALSE, NULL, NULL, NULL);
