INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3129, 1455, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 5 достижения «Свобода».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1456, 75, 570);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3130, 1456, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите одну часть достижения «Время идёт (глава 5)».  Если в вашей локации есть хотя бы один путеводный камень, погасите один из них.  Каждый персонаж получает 1 @Terror@.   Поместите 2 красных маркера на карту секрета 10.  Продолжайте игру.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1457, 75, 571);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3131, 1457, 0, 'condition', 'Если у вас есть синий светофильтр.', 'verse', 571, NULL, NULL, 'Вдруг под ближайшим кустом что-то блеснуло. Вы подошли поближе и нашли небольшой флакон с мерцающей жидкостью.  Получите 1 магию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3132, 1457, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Можете получить 1 @Terror@ и 2 еды.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1458, 75, 572);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3133, 1458, 0, 'condition', 'Если у вас есть часть 3 достижения «Страхи и напасти», но нет части 4 достижения «Горькая правда».', 'cross_location', 921, 1001, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3134, 1458, 1, 'condition', 'Если вы проходите главу 9Б или 10.', 'end', NULL, NULL, NULL, 'Здесь больше нечего смотреть.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3135, 1458, 2, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Если у вас нет части 6 достижения «Трофеи искаженья», каждый член команды получает 1 @Health@ и теряет 2 @Terror@. Затем получите часть и достижения «Трофеи искаженья».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1459, 75, 573);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3136, 1459, 0, 'condition', 'Если у вас нет части 3 достижения «Наглость».', 'verse', 575, NULL, NULL, 'Не успела стража выдворить вас прочь, как король Лот очнулся и вмешался.  — Шериф, постой! Эта особа уже доказала, что достойна моего доверия. Пусть приступает к работе, а ты разгони всех бесполезных зевак.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3137, 1459, 1, 'condition', 'Если у вас есть часть 9 достижения «Небольшая услуга».', 'verse', 575, NULL, NULL, 'Не успела стража выдворить вас прочь, как вмешался Аэд.  — Шериф, уходи! Пусть поиском улик займётся тот, кому я доверяю. А ты лучше сделай что-нибудь, чтобы разогнать этих бесполезных зевак.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3138, 1459, 2, 'condition', 'Если у вас есть часть 6 достижения «Небольшая услуга».', 'verse', 575, NULL, NULL, 'Не успела стража выдворить вас прочь, как раздался пронзительный крик. Толпа расступилась, освобождая путь для близнецов в паланкине.  — Молчать! Всем молчать! Ты! Мы верим только тебе. / Во что бы то ни стало раскрой это чудовищное преступление.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3139, 1459, 3, 'condition', 'В противном случае.', 'verse', 511, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1460, 75, 574);
