INSERT INTO verses (id, location_id, display_number) VALUES (1461, 75, 575);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3141, 1461, 0, 'choice', '1—6.', 'verse', 506, NULL, NULL, 'Долгие поиски не принесли результата. Вам пришлось признать поражение.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3142, 1461, 1, 'choice', '≥7.', 'verse', 224, NULL, NULL, 'Вы нашли кое-что интересное!', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1462, 75, 576);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3143, 1462, 0, 'choice', 'Рассказать предтече историю о том, как появились люди.', 'verse', 579, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3144, 1462, 1, 'choice', 'Рассказать предтече историю про Артура Пендрагона и о том, как он стал королём.', 'verse', 582, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1463, 75, 577);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3145, 1463, 0, 'choice', 'Продолжить.', 'verse', 578, NULL, NULL, 'Получите часть 6 достижения «Топография».  Сбросьте из локации 122 все @LightTT@.  Приложите локацию 125 («Южные земли») снизу к локации 126 («Отвоёванные земли») @Clear@ стороной вверх. Переместите всех персонажей в локацию 125, не применяя её @Thunder@ эффект.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1464, 75, 578);
