INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3150, 1467, 1, 'condition', 'Если у вас есть часть 3 достижения «Строители Сурлузы».', 'cross_location', 657, 1001, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3151, 1467, 2, 'condition', 'Если у вас есть часть 2 достижения «Строители Сурлузы».', 'verse', 517, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3152, 1467, 3, 'condition', 'Нажмите сюда, если хотите увидеть подсказку.', 'verse', 581, NULL, NULL, 'Подсказка: по всей видимости, искаженье скапливалось там, где в кладке мостовой не хватало светящихся камней. Может быть, вам поможет, если заполнить выбоины светящимся камнем?', NULL, FALSE, NULL, NULL, NULL);
