INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3154, 1468, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Откройте и прочитайте новую карту события.   Затем исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1469, 75, 583);
