INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3156, 1469, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый персонаж получает 1 опыт.  Получите часть 5 достижения «Трофеи искаженья».   Уберите 2 красных маркера с карты секрета 10.   Продолжайте игру.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1470, 75, 584);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3157, 1470, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Уберите 2 красных маркера с карты секрета 10.   Каждый персонаж получает 1 @Health@, 1 @Energy@ и теряет 1 @Terror@.   Продолжайте игру.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1471, 75, 585);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3158, 1471, 0, 'choice', '1—8.', 'verse', 300, NULL, NULL, 'Он вас услышал!   Поместите фигурку Клаудина Непосвящённого в вашу локацию.   Получите секретную карту 145.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3159, 1471, 1, 'choice', '≥9.', 'verse', 590, NULL, NULL, 'Вам удалось подойти достаточно близко, чтобы расслышать его шёпот.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1472, 75, 586);
