INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3163, 1474, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Вы освоили новое действие дипломатии. Получите секретную карту 123 (карта дипломатии «Рука помощи») и замешайте её в колоду дипломатии Гердвин.  Получите часть 1 достижения «Свобода» и часть 4 достижения «Случайные встречи».  Гердвин получает 1 опыт.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
