INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3168, 1478, 0, 'choice', '1.', 'verse', 594, NULL, NULL, 'Туман впился в ваше тело, как голодный зверь.   Каждый персонаж теряет 2 @Health@ (–1 за каждое очко своей @Aggression@).', NULL, FALSE, NULL, NULL, NULL);
