INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3170, 1478, 2, 'choice', '3—4.', 'verse', 594, NULL, NULL, 'Вы наткнулись на нечто ужасное.   Возьмите фиолетовую карту встречи и проведите её.', NULL, FALSE, NULL, NULL, NULL);
