INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3189, 1487, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'o Получите одну часть достижения «Время идёт (глава 4)».  o Каждый персонаж восстанавливает @Health@ и @Energy@ до максимального значения.  o Каждый персонаж, у которого более 5 еды, золота или магии, уменьшает свою еду, золото и магию до 5.  o Каждый персонаж, у которого менее 5 магии, увеличивает свою магию до 5.  Обратите внимание: если у вас есть не все части достижения «Неудачи Непосвящённого», рассмотрите возможность отыскать больше информации о правлении Клаудина — его проступках и слабостях. Это поможет вам в решающей схватке.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
