INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3217, 1500, 0, 'choice', '0—2.', 'verse', 676, NULL, NULL, 'Вы были слишком медлительны. Пламя настигло вас, и вы упали вниз в облаке пылающих обломков.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3218, 1500, 1, 'choice', '3—4.', 'verse', 630, NULL, NULL, 'Вы едва успели, но всё же смогли перепрыгнуть на следующую часть моста, хотя и обожглись.   Каждый член команды теряет 1 @Health@ и получает 1 @Terror@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3219, 1500, 2, 'choice', '≥5.', 'verse', 630, NULL, NULL, 'Вы опередили пламя и быстро спустились ниже.', NULL, FALSE, NULL, NULL, NULL);
