INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3220, 1501, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Вы освоили новое действие боя или дипломатии. Возьмите секретные карты 128 (карта боя «Повелительница оружия») и 133 (карта дипломатии «Целебное масло»). Выберите одну из них и замешайте в соответствующую колоду. Уберите другую карту из игры.  Юнис получает 1 опыт.  Получите часть 7 достижения «Личные дела».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1502, 76, 616);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3221, 1502, 0, 'choice', 'Продолжить.', 'verse', 685, NULL, NULL, 'Поместите в эту локацию 1 @DarkTT@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1503, 76, 617);
INSERT INTO verses (id, location_id, display_number) VALUES (1504, 76, 618);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3222, 1504, 0, 'choice', 'Ответить, что Мерлин желал увезти Артура от кровожадного Утера и его бесконечных войн, от двора, где единственного наследника избаловали бы сверх меры. Вместо этого у юного Артура было обычное детство, а его наставником стал один из достойнейших рыцарей королевства.', 'verse', 608, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3223, 1504, 1, 'choice', 'Ответить, что Мерлин хотел убедиться, что все безоговорочно признают Артура законным правителем. Королевство Утера было создано недавно, и после его смерти Артур мог столкнуться с мятежом со стороны других лордов. Необычайная история о мече и камне разнеслась по всему королевству. Теперь окрестные государства вряд ли могли объявить войну «королю из пророчества».', 'cross_location', 591, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1505, 76, 619);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3224, 1505, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 5 достижения «Странные уроки».  Каждый персонаж получает 1 опыт.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1506, 76, 620);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3225, 1506, 0, 'choice', 'Защититься от искаженья.', 'end', NULL, NULL, 'Потратьте 1 магию за персонажа или сбросьте одноразовый предмет «Дивосвеча».', 'Переместите всех членов команды в локацию 125.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3226, 1506, 1, 'choice', 'Пройти через искаженье.', 'end', NULL, NULL, NULL, 'Каждый член команды теряет 1 @Health@ и получает 1 @Terror@.   Переместите всех членов команды в локацию 125.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
