INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3229, 1508, 1, 'choice', 'Нет, он дал людям разных государств возможность во что-то верить и так победил.', 'verse', 608, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
