INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3260, 1518, 0, 'choice', 'Он показал рыцарям, что никогда не станет требовать от них того, на что не способен сам. Разумеется, Артур осознавал, на что идёт, но решил, что королевству нужнее правитель, который готов героически пасть в бою или преуспеть, но не прятаться за чужими спинами.', 'verse', 608, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3261, 1518, 1, 'choice', 'Он знал, что сразивший великана покроет себя славой, и не хотел, чтобы такой почёт заслужил другой рыцарь.', 'cross_location', 591, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
