INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3273, 1522, 0, 'choice', 'Ответить, что Артур поступил так, потому что чувствовал личную ответственность за каждого из своих подданных и верил, что жизнь крестьянина так же ценна, как жизнь рыцаря.', 'verse', 641, NULL, NULL, 'Получите одну часть достижения «Уроки вдохновения».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3274, 1522, 1, 'choice', 'Ответить, что Артур поступил так, потому что знал, что королевства строят не рыцари, а фермеры, ремесленники и простые люди.', 'verse', 641, NULL, NULL, 'Получите одну часть достижения «Уроки хитрости».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1523, 76, 637);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3275, 1523, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Если у вас нет части 7 достижения «Смутная догадка», каждый член команды теряет 2 @Terror@. Затем получите часть 7 достижения «Смутная догадка».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1524, 76, 638);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3276, 1524, 0, 'choice', '0—2.', 'verse', 676, NULL, NULL, 'Вы были слишком медлительны. Пламя настигло вас, и вы упали вниз в облаке пылающих обломков.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3277, 1524, 1, 'choice', '3—4.', 'verse', 623, NULL, NULL, 'Вы едва успели, но всё же смогли перепрыгнуть на следующую часть моста, хотя и обожглись.   Каждый член команды теряет 1 @Health@ и получает 1 @Terror@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3278, 1524, 2, 'choice', '≥5.', 'verse', 623, NULL, NULL, 'Вы опередили пламя и быстро спустились ниже.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1525, 76, 639);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3279, 1525, 0, 'choice', 'Купить еду.', 'verse', 639, NULL, 'Потратьте 2 золота.', 'Получите 1 еду.   Сделайте новый выбор.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3280, 1525, 1, 'choice', 'Продать еду.', 'verse', 639, NULL, 'Потратьте 2 еды.', 'Получите 1 золото.   Сделайте новый выбор.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3281, 1525, 2, 'choice', 'Купить снаряжение.', 'verse', 639, NULL, NULL, 'Если вы проходите главу 6А, 7А, 8А или 9Б, возьмите 3 предмета В.   Если вы проходите главу 6Б, 7Б, 8Б или 9А, возьмите 3 предмета Г.  Можете купить любые из них, потратив 4 золота за каждый. Замешайте некупленное обратно в соответствующую колоду.   Сделайте новый выбор (в этом исследовании выбрать этот вариант больше нельзя).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3282, 1525, 3, 'choice', 'Продать снаряжение.', 'verse', 639, NULL, 'Сбросьте 1 предмет.', 'Получите 1 золото.  Сделайте новый выбор.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3283, 1525, 4, 'choice', 'Купить одноразовые предметы.', 'verse', 639, NULL, NULL, 'Возьмите 3 одноразовых предмета. Можете купить любые из них, потратив 2 золота за каждый. Замешайте некупленное обратно в колоду одноразовых предметов.   Сделайте новый выбор (в этом исследовании выбрать этот вариант больше нельзя).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3284, 1525, 5, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
