INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3326, 1544, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Вы освоили новое действие боя или дипломатии. Возьмите секретные карты 117 (карта боя «Ослепляющая стрела») и 122 (карта дипломатии «Второй шанс»). Выберите одну из них и замешайте в соответствующую колоду. Уберите другую карту из игры.  Гердвин получает 1 опыт.  Получите часть 10 достижения «Заготовки».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1545, 76, 659);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3327, 1545, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Вы освоили новое действие боя или дипломатии. Возьмите секретные карты 127 (карта боя «Решающий удар») и 132 (карта дипломатии «Последнее слово»). Выберите одну из них и замешайте в соответствующую колоду. Уберите другую карту из игры.   Юнис получает 1 опыт.  Получите часть 11 достижения «Заготовки».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1546, 76, 660);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3328, 1546, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый член команды теряет 2 @Energy@ и получает 2 @Terror@.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1547, 76, 661);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3329, 1547, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый член команды получает 1 @Terror@ и теряет 1 @Health@.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1548, 76, 662);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3330, 1548, 0, 'choice', '1 @Energy@ Пойти в личные покои Венеды.', 'verse', 724, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3331, 1548, 1, 'choice', '1 @Energy@ Навестить семейство князя Аскольда.', 'verse', 721, NULL, 'Нужна часть 2 достижения «Случайные встречи»; только если у вас нет части 1 достижения «Союз Чернолесья».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3332, 1548, 2, 'choice', 'Украсть всё, что плохо лежит, и поджечь дворец. Это станет тяжёлым ударом для Венеды.', 'verse', 727, NULL, 'Только если у вас нет ни части 9 достижения «Бессердечность», ни части 1 достижения «Союз Чернолесья».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3333, 1548, 3, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1549, 76, 663);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3334, 1549, 0, 'choice', '', 'end', NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1550, 76, 664);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3335, 1550, 0, 'choice', 'Спросить, почему она осталась так близко к Влинскому. Не слишком ли это было рискованно?', 'verse', 678, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3336, 1550, 1, 'choice', 'Спросить, видела ли она Андро.', 'verse', 686, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3337, 1550, 2, 'choice', 'Спросить, можете ли вы чем-то помочь.', 'verse', 689, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3338, 1550, 3, 'choice', 'Закончить разговор.', 'verse', 692, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1551, 76, 665);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3339, 1551, 0, 'choice', '1—2.', 'verse', 914, NULL, NULL, 'Янтарная царица и её отродья напали на вас.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3340, 1551, 1, 'choice', '3—4.', 'verse', 915, NULL, NULL, 'Янтарная царица приблизилась — она была согласна на переговоры.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3341, 1551, 2, 'choice', '5.', 'end', NULL, NULL, NULL, 'Личная охрана и янтарные отродья помогли янтарной царице прогнать вас.   Переместите всех членов команды в любую связанную локацию.   Каждый член команды теряет 1 @Energy@.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3342, 1551, 3, 'choice', '≥6.', 'end', NULL, NULL, NULL, 'Когда вы подошли, янтарная царица снова растаяла в тумане.  Уберите с поля фигурку янтарной царицы Венеды.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1552, 76, 666);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3343, 1552, 0, 'choice', 'Провести ритуал, помочь демону и козе освободиться. Если всё пойдёт по плану, Вузиэль вернётся в свой родной мир, а чародей снова обретёт человеческое тело.', 'verse', 1093, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3344, 1552, 1, 'choice', 'Изменить ритуал: пусть демон отправляется в тело козы. Если переставить местами несколько символов, Вузиэль окажется в теле козы, как и задумывал чародей.', 'verse', 1110, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1553, 76, 667);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3345, 1553, 0, 'choice', 'Продолжить.', 'verse', 668, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1554, 76, 668);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3346, 1554, 0, 'choice', 'Продолжить.', 'verse', 664, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
