INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3347, 1555, 0, 'choice', 'Продолжить.', 'verse', 668, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
