INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3349, 1556, 1, 'condition', 'Если вы проходите главу 7Б, часть 4.', 'verse', 673, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3350, 1556, 2, 'condition', 'Если вы проходите главу 8Б.', 'verse', 739, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3351, 1556, 3, 'choice', '1.', 'end', NULL, NULL, NULL, 'Ноний, владыка глубин, вызвал ужасную бурю, и вы заблудились.  Выберите связанную локацию и переместите туда всех членов команды. Каждый член команды тратит 1 магию или теряет 1 @Energy@.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3352, 1556, 4, 'choice', '2, 4.', 'cross_location', 203, 999, NULL, 'Ноний вскинул посох и приготовился атаковать.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3353, 1556, 5, 'choice', '3, 5.', 'cross_location', 205, 999, NULL, 'Ноний издалека окликнул вас и спросил, как вы смеете вторгаться в земли фоморов.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3354, 1556, 6, 'choice', '≥6.', 'verse', 1210, NULL, NULL, 'Внушительная фигура Нония высилась под дождём. Он ждал, что вы будете делать.   Поместите по 1 @QuestToken@ на планшеты персонажей всех членов команды.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1557, 76, 671);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3355, 1557, 0, 'choice', 'Приготовиться к бою.', 'cross_location', 326, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3356, 1557, 1, 'choice', 'Попробовать с ним договориться.', 'cross_location', 328, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3357, 1557, 2, 'choice', 'Отступить.', 'end', NULL, NULL, NULL, 'Переместите всех членов команды в локацию 154 («Латифундии») или 153 («Угрюмый хребет»).   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1558, 76, 672);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3358, 1558, 0, 'condition', 'Если Элган в этой локации и у вас есть часть 1 достижения «Путники из прошлого», но нет части 1 достижения «Уроки прошлого».', 'verse', 765, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3359, 1558, 1, 'condition', 'Если Гердвин в этой локации и у вас есть часть 2 достижения «Путники из прошлого», но нет части 2 достижения «Уроки прошлого».', 'verse', 769, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3360, 1558, 2, 'condition', 'Если Осберт в этой локации и у вас есть часть 3 достижения «Путники из прошлого», но нет части 3 достижения «Уроки прошлого».', 'verse', 775, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3361, 1558, 3, 'condition', 'Если Юнис в этой локации и у вас есть часть 4 достижения «Путники из прошлого», но нет части 4 достижения «Уроки прошлого».', 'verse', 782, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1559, 76, 673);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3362, 1559, 0, 'condition', 'Если в этой локации есть хотя бы 1 @QuestToken@ и присутствуют все персонажи.', 'verse', 690, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3363, 1559, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Переместите всех членов команды в связанную локацию.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1560, 76, 674);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3364, 1560, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите одну часть достижения «Время идёт (глава 5)».  Уберите особое событие Д из игры.  Положите особое событие Г на колоду событий. Затем положите  сверху 6 (− 1 за персонажа) случайных событий.  Откройте и прочитайте новую карту события.   Затем исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1561, 76, 675);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3365, 1561, 0, 'condition', 'Если вы победили.', 'verse', 679, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
