INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3367, 1562, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'o Каждый член команды получает 2 @Terror@.  o Каждый член команды теряет 6 @Health@ (–2 за каждый красный маркер в этой локации).  o Уберите 3 красных маркера (–1 за каждый красный маркер в этой локации) с карты секрета 10 (если вам потребуется перейти к другой строфе, сделайте это после окончания исследования).  o Уберите все красные маркеры из этой локации.  o Поместите 1 @DarkTT@ в эту локацию.  o Если локация 105-Б («Брошенный лагерь») не приложена снизу локации 109, приложите её сейчас.  o Переместите всех членов команды и спутников в локацию 105-Б.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
