INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3381, 1570, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 7 достижения «Великие деяния».  Уберите с поля фигурку янтарной царицы Венеды и верните секретную карту 160 в секретную колоду.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1571, 76, 685);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3382, 1571, 0, 'choice', '0—2.', 'verse', 676, NULL, NULL, 'Вы были слишком медлительны. Пламя настигло вас, и вы упали вниз в облаке пылающих обломков.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3383, 1571, 1, 'choice', '3—4.', 'verse', 711, NULL, NULL, 'Вы едва успели, но всё же смогли перепрыгнуть на следующую часть моста, хотя и обожглись.   Каждый член команды теряет 1 @Health@ и получает 1 @Terror@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3384, 1571, 2, 'choice', '≥5.', 'verse', 711, NULL, NULL, 'Вы опередили пламя и быстро спустились вниз.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1572, 76, 686);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3385, 1572, 0, 'choice', 'Продолжить.', 'verse', 664, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
