INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3387, 1573, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый член команды теряет 1 золото и 1 @Energy@.   Затем переместите всех членов команды в связанную локацию с наименьшим номером.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1574, 76, 688);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3388, 1574, 0, 'choice', 'Продолжить.', 'verse', 685, NULL, NULL, 'Уберите 2 красных маркера с карты секрета 10 (если вам потребуется перейти к другой строфе, сделайте это после окончания исследования).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1575, 76, 689);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3389, 1575, 0, 'choice', 'Продолжить.', 'verse', 664, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1576, 76, 690);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3390, 1576, 0, 'condition', 'Если у вас есть 2 красных маркера на карте секрета 50.', 'verse', 647, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3391, 1576, 1, 'condition', 'В противном случае.', 'verse', 1240, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
