INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3392, 1577, 0, 'choice', 'Продолжить.', 'verse', 682, NULL, NULL, 'Осберт получает 1 @Terror@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1578, 76, 692);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3393, 1578, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 2 достижения «Горькая правда».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1579, 76, 693);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3394, 1579, 0, 'choice', 'Дать Кливару знак вырваться и укусить незнакомца. Дело рискованное, но вам не привыкать.', 'verse', 691, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3395, 1579, 1, 'choice', 'Передать грамоту. Да, грамота — это ваше будущее. Но как же Кливар? Он вам как родной, больше у вас никого нет.', 'verse', 697, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3396, 1579, 2, 'choice', 'Спросить незнакомца, зачем он так поступает.', 'verse', 695, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1580, 76, 694);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3397, 1580, 0, 'choice', '...фоморы. Как бы вы к ним ни относились, у вас был общий враг — предтечи. Если они победят и придут к власти, это в равной мере навредит Лотиану и Венедии.', 'end', NULL, NULL, NULL, 'Получите одну часть достижения «Преимущество: вода».  Поместите 1 красный маркер на карту секрета 50.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3398, 1580, 1, 'choice', '...предтечи. Если сейчас ослабить Нония, ему придётся труднее в грядущих боях. Вы готовы на всё ради достижения своей цели, невзирая на последствия.', 'end', NULL, NULL, NULL, 'Получите одну часть достижения «Преимущество: искаженье».  Поместите 1 красный маркер на карту секрета 50.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1581, 76, 695);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3399, 1581, 0, 'choice', 'Продолжить.', 'verse', 693, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1582, 76, 696);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3400, 1582, 0, 'condition', 'Если в этой локации есть @LightTT@.', 'end', NULL, NULL, NULL, 'Вы пришли слишком рано.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3401, 1582, 1, 'condition', 'Если у вас есть часть 6 достижения «Осведомитель».', 'verse', 702, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3402, 1582, 2, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Если у вас нет части 9 достижения «Странные уроки», каждый персонаж получает 1 опыт.   Получите часть 9 достижения «Странные уроки».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1583, 76, 697);
