INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3404, 1584, 0, 'choice', 'Купить еду.', 'verse', 698, NULL, 'Потратьте 2 золота.', 'Получите 1 еду.   Сделайте новый выбор.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3405, 1584, 1, 'choice', 'Продать еду.', 'verse', 698, NULL, 'Потратьте 2 еды.', 'Получите 1 золото.   Сделайте новый выбор.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3406, 1584, 2, 'choice', 'Купить снаряжение.', 'verse', 698, NULL, NULL, 'Возьмите 3 предмета A. Можете купить любые из них, потратив 2 золота за каждый. Замешайте некупленное обратно в колоду предметов А.   Сделайте новый выбор (в этом исследовании выбрать этот вариант больше нельзя).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3407, 1584, 3, 'choice', 'Продать снаряжение.', 'verse', 698, NULL, 'Сбросьте 1 предмет.', 'Получите 1 золото.  Сделайте новый выбор.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3408, 1584, 4, 'choice', 'Купить одноразовые предметы.', 'verse', 698, NULL, NULL, 'Возьмите 3 одноразовых предмета. Можете купить любые из них, потратив 1 золото за каждый. Замешайте некупленное обратно в колоду одноразовых предметов.   Сделайте новый выбор (в этом исследовании выбрать этот вариант больше нельзя).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3409, 1584, 5, 'choice', 'Попробовать уйти.', 'end', NULL, NULL, 'Если у вас есть часть 5 достижения «Небольшая услуга».', 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3410, 1584, 6, 'choice', 'Попробовать уйти.', 'cross_location', 228, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
