INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3418, 1586, 2, 'condition', 'Если вы находитесь в локациях 151—162.', 'verse', 860, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3419, 1586, 3, 'condition', 'Если вы находитесь в локациях 112—126.', 'verse', 700, NULL, NULL, 'Добавьте 700 к номеру текущей локации и выберите секрет с получившимся номером на главном экране.   Например: если вы в локации 112, выберите секрет 812.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3420, 1586, 4, 'condition', 'В противном случае.', 'end', NULL, NULL, NULL, 'Кендрику нечего вам сказать.   Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
