INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3421, 1587, 0, 'condition', 'Если вы проходите главу 10.', 'verse', 1135, NULL, NULL, 'Если под картой секрета 20 есть предмет, сбросьте его.  Верните карту секрета 20 в колоду секретов.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3422, 1587, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Если под картой секрета 20 есть предмет, сбросьте его.  Верните карту секрета 20 в колоду секретов.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1588, 76, 702);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3423, 1588, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Если у вас нет части 9 достижения «Странные уроки», каждый персонаж получает 1 опыт. Получите часть 9 достижения «Странные уроки».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1589, 76, 703);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3424, 1589, 0, 'choice', 'Отдать знамя. Приказать выжившим вернуться в лагерь в Лотиане и восстановить его. Имя Железной дружины будет стёрто из истории, но её воины продолжат своё дело под новыми знамёнами.', 'verse', 771, NULL, NULL, 'Получите часть 11 достижения «Личные дела».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3425, 1589, 1, 'choice', 'Убедить венедцев не забирать знамя у дружины. Приказать выжившим вернуться в лагерь в Лотиане и восстановить его. Да, венедцам это придётся не по душе, но Железная дружина сохранит своё знамя.', 'verse', 771, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3426, 1589, 2, 'choice', 'Распустить дружину, поделить её казну и приказать выжившим отправляться восвояси. Запятнанная история Железной дружины закончится здесь и сейчас. Пусть здешние дружинники и те, кто остался в Лотиане, идут куда захотят. Они вправе искать любого будущего, как и вы.', 'cross_location', 348, 999, NULL, 'Получите часть 12 достижения «Личные дела».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1590, 76, 704);
