INSERT INTO verses (id, location_id, display_number) VALUES (1597, 76, 711);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3458, 1597, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1598, 76, 712);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3459, 1598, 0, 'choice', 'Согласиться пойти с ней. Вы сможете сменить сторону позже.', 'verse', 748, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3460, 1598, 1, 'choice', 'Отказаться.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1599, 76, 713);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3461, 1599, 0, 'choice', 'Продолжить.', 'verse', 913, NULL, NULL, 'Получите одну часть достижения «Преимущество: искаженье».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1600, 76, 714);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3462, 1600, 0, 'condition', 'Если у вас есть часть 5 или 6 достижения «Конец пути».', 'verse', 989, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3463, 1600, 1, 'choice', 'Попросить их вернуться с вами в Лотиан. Вы одна семья и вместе вернётесь туда, где всё началось, чтобы восстановить старую мастерскую. Затем, когда вы избавитесь от клейма, то сможете осесть там навсегда.', 'verse', 1026, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3464, 1600, 2, 'choice', 'Пусть остаются жить в Фомории. Лисса с Каем останутся в своей новой мастерской и продолжат жить, как жили, а вы будете иногда их навещать.', 'verse', 1075, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1601, 76, 715);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3465, 1601, 0, 'choice', '0—6.', 'verse', 716, NULL, NULL, 'Вы не смогли их убедить. Они обнажили мечи.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3466, 1601, 1, 'choice', '≥7.', 'verse', 719, NULL, NULL, 'Они успокоились. Вы смогли подняться на перевал.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1602, 76, 716);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3467, 1602, 0, 'choice', 'Продолжить.', 'verse', 719, NULL, NULL, 'Уберите 2 красных маркера с карты секрета 10 (если вам потребуется перейти к другой строфе, сделайте это после окончания исследования).  Каждый персонаж получает 2 @Terror@.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1603, 76, 717);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3468, 1603, 0, 'condition', 'Если вы проходите главу 9Б.', 'verse', 951, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3469, 1603, 1, 'choice', 'Дружина сдаётся: попробовать обсудить условия. Рольф не прислушается к вам, но его люди, возможно, послушают. Учитывая, что Валеска вам должна, у вас есть шанс договориться о безопасном отступлении для оставшейся части дружины.', 'verse', 703, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3470, 1603, 2, 'choice', 'Пусть венедцы сами разбираются с дружиной. Большинство воинов дружины погибнут в бою, а остальные попадут в плен. История Железной дружины закончится здесь и сейчас, но не вы выбрали для неё этот путь.', 'verse', 728, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1604, 76, 718);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3471, 1604, 0, 'choice', '0—6.', 'verse', 716, NULL, NULL, 'Вы не смогли их убедить. Они обнажили мечи.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3472, 1604, 1, 'choice', '≥7.', 'verse', 719, NULL, NULL, 'Вам удалось разрядить обстановку. Вы смогли подняться на перевал.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1605, 76, 719);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3473, 1605, 0, 'choice', 'Если у вас есть часть 1 достижения «Спутники».', 'verse', 666, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3474, 1605, 1, 'choice', 'В противном случае.', 'end', NULL, NULL, NULL, 'Исследуйте локацию 111.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1606, 76, 720);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3475, 1606, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Верните карту секрета 20 в колоду секретов.  Получите часть 1 достижения «Следопыт».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1607, 76, 721);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3476, 1607, 0, 'choice', 'Продолжить.', 'verse', 740, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1608, 76, 722);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3477, 1608, 0, 'choice', 'Попросить предтечу снять доспех. Без него он станет меньше и будет казаться больше похожим на человека.', 'verse', 731, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3478, 1608, 1, 'choice', 'Попытаться проскользнуть ночью. В темноте ваш союзник будет не так бросаться в глаза, но ночные патрули более подозрительны.', 'verse', 741, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3479, 1608, 2, 'choice', 'Идти вперёд. По тропе нынче ходят многие необычные путники, включая нескольких фоморов. Вы надеялись, что никто не обратит внимания на ещё одну странную фигуру.', 'verse', 749, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3480, 1608, 3, 'choice', 'Уйти.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1609, 76, 724);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3481, 1609, 0, 'choice', '0—2.', 'end', NULL, NULL, NULL, 'Вы в ужасе бежали. Стража обнаружила ваше присутствие!  Найдите карту встречи «Рыцарь-подлец» (зелёная, сложность 3) и проведите её. Вне зависимости от её итога исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3482, 1609, 1, 'choice', '3—4.', 'verse', 662, NULL, NULL, 'Давящая атмосфера заставила вас отступить.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3483, 1609, 2, 'choice', '≥5.', 'verse', 732, NULL, NULL, 'Вы сумели преодолеть защиту!', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1610, 76, 725);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3484, 1610, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый персонаж получает 2 опыта.   Получите часть 8 достижения «Свобода».   Получите часть 7 достижения «Будущее Авалона».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1611, 76, 726);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3485, 1611, 0, 'choice', 'Продолжить.', 'verse', 746, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1612, 76, 727);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3486, 1612, 0, 'condition', 'Если вы проходите главу 9Б.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3487, 1612, 1, 'condition', 'В противном случае.', 'verse', 980, NULL, 'Получите часть 1 достижения «Союз Чернолесья».   Если у вас теперь есть хотя бы три части достижения «Союз Чернолесья».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3488, 1612, 2, 'condition', 'В противном случае.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
