INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3495, 1616, 1, 'choice', 'Идти вперёд. По тропе нынче ходят многие необычные путники, включая нескольких фоморов. Вы надеялись, что никто не обратит внимания на ещё одну странную фигуру.', 'verse', 749, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
