INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3496, 1617, 0, 'choice', 'Продолжить.', 'verse', 662, NULL, NULL, 'Получите часть 3 достижения «Тайны янтарной царицы».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1618, 76, 733);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3497, 1618, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1619, 76, 734);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3498, 1619, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1620, 76, 735);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3499, 1620, 0, 'choice', 'Попробовать соорудить тележку, чтобы перевезти тело. Можно использовать обломки боевой колесницы Клаудина, чтобы построить простую телегу.', 'verse', 734, NULL, 'Нужно хотя бы 3 очка @Practicality@.', 'Получите карту секрета 2.  Поместите 1 @QuestToken@ на карту секрета 2.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3500, 1620, 1, 'choice', 'Попробовать призвать магию, чтобы перенести тело. Вы достаточно изучили магию, чтобы призвать силу, способную переносить грузы.', 'verse', 734, NULL, 'Нужно хотя бы 3 очка @Spirituality@.', 'Получите карту секрета 2.  Поместите 1 @QuestToken@ на карту секрета 2.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3501, 1620, 2, 'choice', 'Закинуть тело на спину и перетащить. С вашей необыкновенной силой и выносливостью у вас всё получится, хотя кто угодно другой на вашем месте мог и не справиться.', 'verse', 734, NULL, 'Нужно хотя бы 3 очка @Aggression@.', 'Получите карту секрета 2.  Поместите 1 @QuestToken@ на карту секрета 2.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3502, 1620, 3, 'choice', 'Призвать козу — пусть везёт тело. Коза была не рада такой ноше и протестующе заблеяла.', 'verse', 734, NULL, 'Нужна секретная карта 305.', 'Получите карту секрета 2.  Поместите 1 @QuestToken@ на карту секрета 2.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3503, 1620, 4, 'choice', 'Тащить тело по земле.', 'verse', 734, NULL, NULL, 'Получите карту секрета 2.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1621, 76, 736);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3504, 1621, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый член команды теряет 1 @Health@ или получает 1 @Terror@.  Получите часть 2 достижения «Кендрик».  Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1622, 76, 737);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3505, 1622, 0, 'condition', 'Если у вас есть хотя бы три части достижения «Союз Чернолесья».', 'verse', 980, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3506, 1622, 1, 'condition', 'В противном случае.', 'end', NULL, NULL, NULL, 'Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1623, 76, 738);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3507, 1623, 0, 'condition', 'Если у вас нет ни части 3, ни части 4 достижения «Королевские похороны».', 'verse', 881, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3508, 1623, 1, 'condition', 'Если у вас есть часть 3 достижения «Будущее Авалона».', 'verse', 887, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3509, 1623, 2, 'condition', 'В противном случае.', 'verse', 1241, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1624, 76, 739);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3510, 1624, 0, 'condition', 'Если все персонажи здесь.', 'cross_location', 1, 162, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3511, 1624, 1, 'condition', 'В противном случае.', 'end', NULL, NULL, NULL, 'Переместите всех членов команды в локацию 158-Б.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1625, 76, 740);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3512, 1625, 0, 'choice', 'Убедить их, что не стоит больше помогать Венеде.', 'verse', 1242, NULL, NULL, 'Если у вас нет части 3 достижения «Дружба со знатью», каждый член команды теряет 1 @Terror@. Затем получите 2 золота и часть 3 достижения «Дружба со знатью».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3513, 1625, 1, 'choice', 'Пусть сами решают, что делать.', 'verse', 662, NULL, NULL, 'Если у вас нет части 3 достижения «Дружба со знатью», каждый член команды теряет 1 @Terror@. Затем получите 2 золота и часть 3 достижения «Дружба со знатью».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1626, 76, 741);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3514, 1626, 0, 'choice', 'Сказать им, что он рыцарь из замка Лотиан, выполняющий тайную миссию.', 'verse', 715, NULL, NULL, 'Поместите 1 @QuestToken@ в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3515, 1626, 1, 'choice', 'Сказать, что он ваш родич, поражённый искаженьем, и вы ведёте его к древним ведуньям Венедии — может, они сумеют помочь.', 'verse', 715, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3516, 1626, 2, 'choice', 'Сказать, что это их не касается, они не имеют права останавливать путников на перевале.', 'verse', 715, NULL, NULL, 'Поместите 1 красный маркер в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1627, 76, 742);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3517, 1627, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый член команды теряет 2 @Terror@ и 1 @Energy@ и получает 1 еду.   Получите часть 2 достижения «Празднество».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1628, 76, 743);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3518, 1628, 0, 'choice', 'Продолжить.', 'verse', 745, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1629, 76, 744);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3519, 1629, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый персонаж получает 1 опыт.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1630, 76, 745);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3520, 1630, 0, 'choice', 'Спросить, какой вред обильное искаженье может нанести королевству. Ведь могут погибнуть и невинные люди?', 'verse', 747, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3521, 1630, 1, 'choice', 'Поддержать этот план.', 'verse', 750, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3522, 1630, 2, 'choice', 'Отвергнуть план.', 'verse', 780, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3523, 1630, 3, 'choice', 'Предложить другой вариант, не подразумевающий использование искаженья.', 'verse', 784, NULL, 'Нужны хотя бы две части достижения «Союз Чернолесья» и часть 4 достижения «Будущее Авалона».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1631, 76, 746);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3524, 1631, 0, 'choice', 'Продолжить.', 'verse', 913, NULL, NULL, 'Получите одну часть достижения «Преимущество: вода».', NULL, FALSE, NULL, NULL, NULL);
