INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3527, 1632, 2, 'choice', 'Предложить свой вариант.', 'verse', 784, NULL, 'Нужны хотя бы две части достижения «Союз Чернолесья» и часть 4 достижения «Будущее Авалона».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1633, 76, 748);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3528, 1633, 0, 'choice', '…Капреллида должна лишиться положения в сенате.', 'verse', 773, NULL, NULL, 'Получите часть 4 достижения «Бюрократия».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3529, 1633, 1, 'choice', '…Октавия должна лишиться титула Глубочайшей.', 'verse', 777, NULL, NULL, 'Получите часть 4 достижения «Бюрократия».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3530, 1633, 2, 'choice', '…вы случайно здесь оказались. Затем уходите с праздника.', 'end', NULL, NULL, NULL, 'Получите часть 4 достижения «Бюрократия».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1634, 76, 749);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3531, 1634, 0, 'choice', 'Попросить их перестать: вы путешествуете с кузеном, тело и разум которого изуродовало искаженье.', 'verse', 718, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3532, 1634, 1, 'choice', 'Объяснить им, что это не человек, а высокопоставленный фомор инкогнито, которого вы сопровождаете домой.', 'verse', 718, NULL, NULL, 'Поместите 1 @QuestToken@ в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3533, 1634, 2, 'choice', 'Посоветовать им не трогать плащ, а не то заразятся красной смертью.', 'verse', 718, NULL, NULL, 'Поместите 1 красный маркер в эту локацию.', NULL, FALSE, NULL, NULL, NULL);
