INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3549, 1647, 0, 'condition', 'Нажмите сюда, если хотите увидеть решение.', 'verse', 762, NULL, NULL, 'Есть несколько способов раздобыть свят-медовуху.  o У медовара в Жеремье (132), но ему понадобится священный мёд (карта секрета 16), сделанный пчёлами у Блуждающих камней (129). Пчёлам взамен нужно дать нового «сладостного святого» (либо князя Аскольда, который в определённое время может быть найден в локации 129, либо отчаянного добровольца из локации 132-Б).  o Купить во время Праздника венков(132-Б) за сумасшедшую цену.  o Получить в качестве награды за помощь послушнице Чернобога (если игроки помогли ей в локации 131, то могут получить награду в локации 128).  o Получить в награду за помощь в церемонии обрезания волос (в дальнем поселении в локации 130).  Резчиков можно нанять в Жеремье (132).  Получив оба достижения, игроки возвращаются в Сердце чащ (141) и выбирают соответствующий вариант.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3550, 1647, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
