INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3551, 1648, 0, 'choice', 'Продолжать путь. Со временем откроется, что заключено в центре голема. До тех пор пусть ещё вам послужит.', 'end', NULL, NULL, NULL, 'Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3552, 1648, 1, 'choice', 'Очистить оставшийся воск. Ожидание было невыносимо: вы должны узнать ответ прямо сейчас!', 'verse', 652, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
