INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3561, 1656, 0, 'choice', 'После окончания странствий вы вернётесь в лагерь в Лотиане и станете новым командиром. Килан Колдфайр был достойным человеком, но его действия десять лет назад привели дружину к поражению в Лотиане. А Рольф… Что ж, Рольф — это Рольф. Вы справитесь лучше любого из них. К тому же воины дружины уже один раз доверили вам свои жизни.', 'cross_location', 359, 999, 'Только если вы не в искажённой форме.', 'Получите часть 13 достижения «Личные дела».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3562, 1656, 1, 'choice', 'После окончания странствий вы вернётесь в лагерь в Лотиане, чтобы стать разведчиком и проводником. Многие в дружине хотели бы видеть вас командиром, но это было невозможно из-за вашего прискорбного преображения. Впрочем, оно могло сослужить вам добрую службу и помочь оградить дружину от влияния искаженья. Не будет разведчика лучше вас. Вы не могли быть командиром, но в вашем лице они обретут преданного защитника, что ещё важнее.', 'cross_location', 359, 999, 'Только если вы в искажённой форме.', 'Получите часть 14 достижения «Личные дела».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3563, 1656, 2, 'choice', 'Сказать им, что у вас свой путь.', 'cross_location', 348, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1657, 76, 772);
