INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3579, 1665, 1, 'choice', 'Не отступать: вы сами справитесь с Венедой и её армией. Звучит самоубийственно, но, пока клеймо не даёт вам погибнуть, рано или поздно вы наверняка преуспеете — неважно, уйдёт ли на это одна попытка или сто.', 'verse', 811, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
