INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3597, 1678, 0, 'choice', 'Отказаться от притязаний и уйти. Всё будет как раньше. Пусть люди в этих землях сами будут себе хозяевами, сколько смогут, — а вы покинете их.', 'verse', 798, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3598, 1678, 1, 'choice', 'Задёрнуть штору и пойти спать. Вы теперь князь Влинский. Всю жизнь вы были изгнанником, но теперь вы наконец заняли такое положение, что никто больше не сможет так с вами поступать. Это было приятное чувство.', 'verse', 796, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1679, 76, 794);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3599, 1679, 0, 'choice', 'Продолжить.', 'verse', 806, NULL, NULL, 'Персонажи могут обменяться любыми предметами, секретами и/или ресурсами. Затем на выбор переместите одного персонажа в локацию 132 (либо 132-Б), одного — в локацию 135 и двух — в локацию 140. Не применяйте @Thunder@ эффекты в этих локациях.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1680, 76, 795);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3600, 1680, 0, 'choice', 'Продолжить.', 'verse', 799, NULL, NULL, 'Уберите из игры карту секрета 10.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1681, 76, 796);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3601, 1681, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Личная история Осберта подошла к концу. Вы ознакомитесь с её развязкой, когда завершите игру.  o Получите часть 3 достижения «Конец пути».  o Осберт получает 3 опыта.  o Осберт получает 8 золота и 1 предмет Д.  o Осберт получает секретную карту 139 (карта боя «Воспоминания о доме») и секретную карту 144 (карта дипломатии «Уверенность аристократа») и замешивает их в соответствующие колоды.  o Каждый персонаж получает 2 @Health@ и теряет 2 @Terror@.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1682, 76, 797);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3602, 1682, 0, 'choice', 'Продолжить.', 'verse', 806, NULL, NULL, 'Персонажи могут обменяться любыми предметами, секретами и/или ресурсами. Затем на выбор переместите одного персонажа в локацию 132 (либо 132-Б), одного — в локацию 135 и одного — в локацию 140. Не применяйте @Thunder@ эффекты в этих локациях.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1683, 76, 798);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3603, 1683, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Поздравляем! Осберт сделал окончательный выбор в своей личной истории. Вы ознакомитесь с её развязкой, когда завершите игру.  o Получите часть 4 достижения «Конец пути».  o Осберт получает 3 опыта.  o Осберт получает 4 золота и 2 предмета В.  o Осберт получает секретную карту 139 (карта боя «Воспоминания о доме») и секретную карту 144 (карта дипломатии «Уверенность аристократа») и замешивает их в соответствующие колоды.  o Каждый персонаж получает 2 @Health@ и теряет 2 @Terror@.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
