INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3830, 1810, 0, 'choice', 'Продолжить.', 'verse', 945, NULL, NULL, 'o Получите 1 @Terror@.  o Замените фигурку своего персонажа в искажённой форме на обычную.  o Уберите все карты искажённой формы из своих колод боя и дипломатии.  o Уберите жетон персонажа в искажённой форме с планшета персонажа. Замените его на обычный жетон персонажа.  o Проверьте свой навык искажённой формы:  • Если на нём есть маркер характеристики, получите опыт, равный суммарному значению характеристик в этой паре +1, а затем сбросьте этот маркер характеристики.  • Сбросьте ваш навык искажённой формы.  • Получите любой навык на ваш выбор из той пары характеристик, в которых вы только что сбросили навык искажённой формы. Вы можете потратить опыт на повышение характеристики, если это необходимо для получения конкретного навыка.  o Если у вас уже есть 4 навыка в данной паре характеристик, получите любой другой навык. Вы можете потратить опыт на повышение характеристики, если это необходимо для получения конкретного навыка. Если даже в этом случае вы не можете получить никакой навык, получите 6 опыта.  o Улучшите колоды дипломатии и боя.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1811, 76, 926);
