INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3833, 1813, 0, 'choice', 'Продолжить.', 'verse', 971, NULL, NULL, 'Получите часть 9 достижения «Путь Венедии».  Переместите всех персонажей в локацию 128 («Чёрный круг»), не применяя её @Thunder@ эффект.', NULL, FALSE, NULL, NULL, NULL);
