INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3836, 1815, 0, 'condition', 'Нажмите сюда, если хотите увидеть решение.', 'verse', 930, NULL, NULL, 'Отправьтесь к Янтарным берегам (135). Когда вы туда доберётесь, бросок кубика определит, находится ли в локации старая сборщица янтаря. Если её там нет, можете вернуться позже или пойти в рыбацкую деревню, чтобы снова бросить кубик. Поговорите со старухой — это поможет вам продвинуться в выполнении миссии.  В локации 135 также можно найти обе части информации, необходимые для выполнения необязательного задания: одну — при разговоре со сборщицей янтаря, другую — из видения в локации.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3837, 1815, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1816, 76, 931);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3838, 1816, 0, 'condition', 'Нажмите сюда, если хотите увидеть решение.', 'verse', 931, NULL, NULL, 'Отправьтесь к Каменному серпу (133) и плывите к вершине. Либо победите стража вершины, либо покажите ему амулет Янтарного круга, который можно получить на Берёзовых кручах (140), если помочь укротителю избушек. Затем пройдите к древним ведуньям и примите их предложение.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3839, 1816, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
