INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3854, 1825, 0, 'choice', 'Продолжить.', 'verse', 974, NULL, NULL, 'o Уберите из игры секретную карту 160.  o Поместите фигурку янтарной царицы Венеды в локацию 141-Б.  o Переместите всех персонажей в локацию 141-Б.  o Получите секретную карту 174, но пока не применяйте её эффекты.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1826, 76, 941);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3855, 1826, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Верните карту секрета 20 в колоду секретов.  Получите часть 2 достижения «Следопыт».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1827, 76, 942);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3856, 1827, 0, 'condition', 'Нажмите сюда, если хотите увидеть решение.', 'verse', 942, NULL, NULL, 'Отправьтесь в Сердце чащ (141) и выследите янтарное отродье возле горных источников.   Отправьтесь к Берёзовым кручам (140) и обыщите дубраву.   Отправьтесь в Перунгород (137) и осмотрите тёмные овраги.   Наконец, отправьтесь к Бесплодной вершине (136), присоединитесь к торжествам и помогите янтарному отродью получить власть над остальными созданиями.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3857, 1827, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1828, 76, 943);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3858, 1828, 0, 'condition', 'Нажмите сюда, если хотите увидеть решение.', 'verse', 943, NULL, NULL, 'В Арконе (138) проникните во дворец и либо убедите семью князя Аскольда перейти на вашу сторону, либо устройте пожар.  У Берёзовых круч (140) сходите на разбитый корабль разбойников Перунгорода и согласитесь помочь им, затем поднимите морскую цепь в Перунгороде (137) и помогите им выиграть сражение.  На Берёзовых кручах (140) помогите укротителю избушек, а после того как выполните его задание, заберите избушки для Союза Чернолесья.  На Бескрайних нивах (134) убедите местных жителей примкнуть к Союзу.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3859, 1828, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Действие окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1829, 76, 944);
