INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3865, 1831, 2, 'choice', 'Повернуть назад ради собственного блага.', 'end', NULL, NULL, NULL, 'Если вы проходите главу 9Б, переместите всех членов команды в локацию 131. В противном случае переместите всех членов команды в локацию 132.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
