INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3869, 1835, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Получите часть 1 достижения «Грехи владыки».  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
