INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3870, 1836, 0, 'choice', 'Дружина сдаётся: попробовать обсудить условия. Рольф не прислушается к вам, но его люди, возможно, послушают. Варегард перед вами в долгу, и у вас есть шанс договориться о безопасном отступлении для оставшейся части дружины.', 'verse', 703, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3871, 1836, 1, 'choice', 'Пусть венедцы сами разбираются с дружиной. Большинство воинов погибнут в бою, а остальные попадут в плен. История Железной дружины закончится здесь и сейчас, но они сами сделали этот выбор.', 'verse', 728, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1837, 76, 952);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3872, 1837, 0, 'condition', 'Если вы проходите главу 9Б, часть 6.', 'verse', 953, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3873, 1837, 1, 'condition', 'Если все персонажи находятся в локациях 135, 140, 141-Б или 132.', 'verse', 974, NULL, NULL, 'Переместите всех персонажей в локацию 141-Б. Все персонажи присоединяются к этому исследованию.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3874, 1837, 2, 'condition', 'Если кто-либо из персонажей находится в другой локации.', 'end', NULL, NULL, NULL, 'Ещё не все были готовы бросить вызов янтарной царице. Вы понимали: нападение на Венеду необходимо досконально спланировать, придётся пока отложить задуманное.  Прежде чем попытаться приблизиться к царице, убедитесь, что все персонажи находятся в локациях вокруг Сердца чащ.  Переместите всех персонажей из локации 141-Б в любую связанную локацию.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1838, 76, 953);
