INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3890, 1850, 0, 'choice', 'Пусть Изолют делает что хочет. Если что-то пойдёт не так, придётся её спасать.', 'verse', 955, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
