INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3896, 1855, 0, 'choice', 'Приказать выжившим вернуться в лагерь в Лотиане и восстановить его. Имя Железной дружины будет стёрто из истории, но её воины продолжат своё дело под новыми знамёнами.', 'verse', 771, NULL, NULL, 'Получите часть 11 достижения «Личные дела».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3897, 1855, 1, 'choice', 'Распустить дружину, поделить её казну и приказать выжившим отправляться восвояси. Запятнанная история Железной дружины закончится здесь и сейчас. Пусть здешние дружинники и те, кто остался в Лотиане, идут куда захотят. Они вправе искать любого будущего, как и вы.', 'cross_location', 359, 999, NULL, 'Получите часть 12 достижения «Личные дела».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3898, 1855, 2, 'choice', 'Пусть венедцы оставят дружинников в плену и заставят их восстанавливать Венедию. Справедливое решение, но, оставив ваших бывших соратников в плену на чужбине, вы положите конец вашей связи с Железной дружиной.', 'cross_location', 348, 999, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1856, 76, 971);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3899, 1856, 0, 'choice', 'Сказать им, что у вас есть оружие, которого боится Венеда, и показать янтарное яйцо. Это будет ложь во спасение.', 'verse', 973, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3900, 1856, 1, 'choice', 'Сказать, что существо из яйца уже вылупилось, но стало вашим союзником.', 'verse', 976, NULL, 'Нужна часть 8 достижения «Путь Венедии».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3901, 1856, 2, 'choice', 'Сказать, что у вас нет яйца, но вам известно слабое место Венеды.', 'verse', 976, NULL, 'Нужна часть 1 или 2 достижения «Тайны янтарной царицы».', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3902, 1856, 3, 'choice', 'Сказать, что у вас нет яйца, но произнести пламенную речь.', 'verse', 976, NULL, 'Нужно хотя бы 4 очка @Empathy@.', NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3903, 1856, 4, 'choice', 'Сказать, что у вас нет яйца, но они сумеют одержать победу без него.', 'verse', 982, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
