INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3910, 1860, 0, 'choice', '1—2.', 'verse', 975, NULL, NULL, 'Вас преследуют! Бегите! Но куда?   Каждый член команды получает 1 @Terror@.  Бросьте кубик ещё раз.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3911, 1860, 1, 'choice', '3—6.', 'end', NULL, NULL, NULL, 'Вы медленно вернулись по своим следам. Снаружи вы наконец смогли дышать.   Каждый член команды теряет 1 @Energy@.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
