INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (3957, 1884, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'o Получите одну часть достижения «Время идёт» для текущей главы.  o Каждый персонаж восстанавливает @Health@ и @Energy@ до максимального уровня.  o Каждый персонаж, у которого больше 5 еды, золота или магии, уменьшает свой запас еды, золота и магии до 5.  o Каждый персонаж, у которого меньше 5 магии, повышает запас своей магии до 5.  o Переместите каждого персонажа в любую связанную локацию.  o Поместите 4 @LightTT@ на секретную карту 174.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
