INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4114, 1968, 0, 'choice', 'Продолжить.', 'verse', 1152, NULL, NULL, 'Получите часть 10 достижения «Будущее Авалона».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1969, 76, 1084);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4115, 1969, 0, 'choice', 'Продолжить.', 'verse', 1036, NULL, NULL, 'o Получите часть 10 достижения «Бессердечность».  o Каждый персонаж теряет 3 @Energy@ (–1 за каждое очко своей @Aggression@).  o Каждый персонаж получает 2 @Terror@ (–1 за каждое очко своей @Courage@).  o Каждый персонаж сбрасывает 1 предмет.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1970, 76, 1085);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4116, 1970, 0, 'choice', 'Продолжить.', 'verse', 1058, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1971, 76, 1086);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4117, 1971, 0, 'choice', '0—8.', 'end', NULL, NULL, NULL, 'До сих пор вы сосредоточивались на миссии и быстро двигались вперёд, почти не отвлекаясь по пути. Вряд ли кто‑либо смог бы добраться до этих проклятых земель быстрее вас. Но противный голосок у вас в голове зудел, что вы пренебрегли множеством возможностей.   Самое время сделать паузу! Либо сохраните игру и пока что прервитесь, либо продолжайте партию.   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4118, 1971, 1, 'choice', '9—22.', 'end', NULL, NULL, NULL, 'Вы шли к цели долгой и запутанной тропой. На пути вас то и дело подстерегали неприятные неожиданности. Но вы добрались сюда, а обширные познания об Авалоне и тайны, которые вы разгадали по дороге, наверняка ещё сослужат вам добрую службу.  Самое время сделать паузу! Либо сохраните игру и пока что прервитесь, либо продолжайте партию.   Исследование окончено.</i', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4119, 1971, 2, 'choice', '≥23.', 'verse', 1111, NULL, NULL, 'Колыбель наконец лежала перед вами, но вы шли сюда слишком долго. Может быть, вы не сразу выходили победителем в схватке с опасностями Авалона, а может, отвлекались на пустяки. В любом случае вы чувствовали, что не слишком преуспели.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1972, 76, 1087);
