INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4129, 1978, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый персонаж получает 1 опыт.  Уберите из игры фигурку Чёрной козы пустошей и секретную карту 305.  Вы можете получить 1 еду (но точно ли хотите этого?).  Затем исследуйте локацию 111.', NULL, FALSE, NULL, NULL, NULL);
