INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4130, 1979, 0, 'choice', 'Продолжить.', 'verse', 1086, NULL, NULL, 'Каждый персонаж получает 2 опыта.   Важно: вы последний раз получаете бонус в виде опыта в этой кампании. Используйте оставшийся опыт, прежде чем перейти к последним испытаниям в игре.', NULL, FALSE, NULL, NULL, NULL);
