INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4133, 1981, 1, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'Каждый персонаж теряет 1 @Terror@.   Получите часть 3 достижения «Запретная земля».   Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
