INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4134, 1982, 0, 'choice', 'Продолжить.', 'verse', 1112, NULL, NULL, 'Каждый персонаж теряет 4 @Energy@ (–1 за каждое очко своей @Aggression@). Каждый персонаж получает 3 @Terror@ (–1 за каждое очко своей @Courage@).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1983, 76, 1098);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4135, 1983, 0, 'choice', 'Продолжить.', 'end', NULL, NULL, NULL, 'o Получите одну часть достижения «Время идёт» для текущей главы.  o Каждый персонаж восстанавливает @Health@ и @Energy@ до максимального уровня.  o Каждый персонаж, у которого больше 5 еды, золота или магии, уменьшает свой запас еды, золота и магии до 5.  o Каждый персонаж, у которого меньше 5 магии, повышает запас своей магии до 5.  o Переместите всех персонажей в локацию 158-Б.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1984, 76, 1099);
