INSERT INTO verses (id, location_id, display_number) VALUES (1985, 76, 1100);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4137, 1985, 0, 'condition', 'Если вы выбрали эпический режим.', 'end', NULL, NULL, NULL, 'Игра окончена.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4138, 1985, 1, 'condition', 'В противном случае.', 'end', NULL, NULL, NULL, 'Прошло немало времени, но наконец вы сумели подняться на ноги и поковыляли вперёд.  Возьмите фигурку путеводного камня и поместите её в ячейку путеводного камня, которая расположена ближе всего к любым персонажам.   Каждый персонаж получает 2 @Health@ и 2 @Energy@.  Получите две части достижения «Время идёт» для текущей главы.  Продолжайте игру.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (1986, 76, 1101);
