INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4245, 2047, 0, 'choice', 'Остаться и дождаться Короля былого и грядущего. Он оказался в другом времени, но он придёт. Вы знали, что Артур Пендрагон причалит к этим берегам, и неважно когда: через год, пять, десять лет или спустя тысячелетие. И здесь вы будете ждать его, пока не сделаете последний вздох.', 'verse', 1165, NULL, NULL, 'Получите часть 10 достижения «Будущее Авалона».', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4246, 2047, 1, 'choice', 'Вернуться на Западный Авалон. Все мечты Запада оказались бессмысленны. Здесь не найти короля, кроме туатанского.', 'verse', 1161, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4247, 2047, 2, 'choice', 'Вернуться к Багровой колыбели и погрузиться в неё. Возможно, вы исчезнете навсегда. Или возродитесь в ином виде. Кто знает?', 'verse', 1155, NULL, 'Только если у вас нет части 9 достижения «Будущее Авалона». Нужны хотя бы три части достижения «Поворот судьбы» и карта секрета 4.', NULL, NULL, FALSE, NULL, NULL, NULL);
