INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4374, 2128, 0, 'choice', 'Продолжить.', 'verse', 806, NULL, NULL, 'Переместите вашего персонажа в одну из следующих локаций: 132 (либо 132-Б), 135 или 140. Не применяйте @Thunder@ эффекты в этих локациях.  Важно: отряды Валески не смогут сдерживать янтарную царицу вечно. Когда @LightTT@ на секретной карте 174 закончатся, сопротивление Валески будет сломлено, и вам придётся сражаться.', NULL, FALSE, NULL, NULL, NULL);
