INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4378, 2131, 1, 'condition', 'В противном случае.', 'end', NULL, NULL, NULL, 'Вас прогнали из усадьбы.  Новая зацепка: вернитесь в усадьбу и найдите другой способ защитить свои притязания.  Исследование окончено.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO verses (id, location_id, display_number) VALUES (2132, 76, 1247);
