INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4380, 2133, 0, 'choice', '1—2.', 'verse', 1248, NULL, NULL, 'Вы гребли изо всех сил и потеряли часть вещей, которые ушли прямо на дно.  Сбросьте 1 случайный предмет.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4381, 2133, 1, 'choice', '3—4.', 'verse', 1248, NULL, NULL, 'На вас посыпался град стрел. Многие из них достигли своей цели.  Потеряйте 3 @Health@ (–1, если у вас есть предмет с ключевым словом «броня»).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4382, 2133, 2, 'choice', '5.', 'verse', 1248, NULL, NULL, 'Одна стрела немного задела вас.  Потеряйте 1 @Health@ (–1, если у вас есть предмет с ключевым словом «броня»).', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4383, 2133, 3, 'choice', '6.', 'verse', 1248, NULL, NULL, 'В воду вокруг посыпался град стрел, но вас не задело.   Ничего не произошло.', NULL, FALSE, NULL, NULL, NULL);
INSERT INTO options (id, verse_id, position, type, text, target_type, target_verse_dn, target_location_dn, requirement, result, hidden, once, condition_group, conditional_targets, children) VALUES (4384, 2133, 4, 'choice', 'Если все персонажи бросили кубик.', 'verse', 871, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL);
